  {"question": "نظریه ریسمان (String Theory) چه ادعایی در مورد ماهیت بنیادی جهان دارد؟", "answer": "نظریه ریسمان فرض می‌کند که ذرات بنیادی بنیادی‌ترین اجزای سازنده جهان نیستند، بلکه رشته‌های کوچک و یک‌بعدی انرژی هستند که با ارتعاش در ابعاد بالاتر، ذرات مختلف را ایجاد می‌کنند."},
  {"question": "ابرتقارن (Supersymmetry) چه رابطه‌ای بین فرمیون‌ها و بوزون‌ها برقرار می‌کند؟", "answer": "ابرتقارن یک تقارن نظری بین فرمیون‌ها (ذرات ماده) و بوزون‌ها (ذرات نیرو) است. بر اساس این نظریه، هر ذره بنیادی باید یک ذره ابرمتقارن (سوپرپارتنر) داشته باشد."},
  {"question": "واسط‌های مغز و کامپیوتر (BCI) چگونه امکان ارتباط مستقیم بین مغز و دستگاه‌های خارجی را فراهم می‌کنند؟", "answer": "BCI ها سیگنال‌های مغزی را از طریق الکترودها (داخلی یا خارجی) دریافت کرده و آن‌ها را به دستوراتی برای کنترل دستگاه‌های خارجی مانند کامپیوتر، بازوهای رباتیک، یا پروتزها تبدیل می‌کنند."},
  {"question": "پردازش عصبی (Neural Processing) در مغز چگونه اطلاعات را تجزیه و تحلیل می‌کند؟", "answer": "پردازش عصبی شامل شبکه‌های پیچیده‌ای از نورون‌ها است که اطلاعات را از طریق سیگنال‌های الکتروشیمیایی پردازش می‌کنند. این فرآیندها شامل یادگیری، حافظه، ادراک، و تصمیم‌گیری هستند."},
  {"question": "نانومواد زیست‌سازگار (Biocompatible Nanomaterials) چه ویژگی‌هایی دارند و در پزشکی چگونه استفاده می‌شوند؟", "answer": "این نانومواد با بافت‌های زنده سازگارند و برای دارورسانی هدفمند، تصویربرداری پزشکی، و مهندسی بافت مورد استفاده قرار می‌گیرند تا عوارض جانبی را کاهش داده و اثربخشی درمان را افزایش دهند."},
  {"question": "خواص کوانتومی نانوساختارها (Quantum Properties of Nanostructures) چگونه از خواص مواد در مقیاس ماکروسکوپی متفاوت است؟", "answer": "در نانوساختارها، اثرات کوانتومی مانند گسیختگی انرژی و تونل‌زنی کوانتومی برجسته می‌شوند که منجر به خواص نوری، الکترونیکی و مغناطیسی منحصر به فردی می‌شود."},
  {"question": "زیست‌شناسی سیستم‌ها (Systems Biology) رویکردی کل‌نگر به مطالعه سیستم‌های زیستی دارد. چگونه؟", "answer": "زیست‌شناسی سیستم‌ها به جای مطالعه اجزای منفرد، به تعاملات بین اجزای مختلف یک سیستم زیستی (مانند ژن‌ها، پروتئین‌ها، و متابولیت‌ها) و نحوه ظهور صفات پیچیده از این تعاملات می‌پردازد."},
  {"question": "دارورسانی نانو (Nanodrug Delivery) چگونه اثربخشی داروها را افزایش داده و عوارض جانبی را کاهش می‌دهد؟", "answer": "نانوحامل‌ها می‌توانند داروها را به طور مستقیم به سلول‌ها یا بافت‌های هدف برسانند، از تجزیه دارو در بدن جلوگیری کنند و آزادسازی کنترل‌شده دارو را امکان‌پذیر سازند، در نتیجه دوز مصرفی و عوارض جانبی را کاهش می‌دهند."},
  {"question": "مهندسی بافت (Tissue Engineering) چگونه بافت‌های جدید را برای پیوند یا ترمیم ایجاد می‌کند؟", "answer": "این رشته با ترکیب سلول‌ها، داربست‌های زیستی (scaffolds) و فاکتورهای رشد، بافت‌های زنده و عملکردی را در آزمایشگاه برای جایگزینی بافت‌های آسیب‌دیده یا از دست رفته ایجاد می‌کند."},
  {"question": "ماده تاریک (Dark Matter) چیست و چه شواهدی برای وجود آن ارائه شده است؟", "answer": "ماده تاریک ماده‌ای فرضی است که نور را جذب یا منعکس نمی‌کند اما اثرات گرانشی آن مشاهده شده است. شواهد وجود آن شامل منحنی چرخش کهکشان‌ها، همگرایی گرانشی، و ساختار مقیاس بزرگ جهان است."},
  {"question": "انرژی تاریک (Dark Energy) چیست و چگونه باعث انبساط شتاب‌دار جهان می‌شود؟", "answer": "انرژی تاریک نیرویی ناشناخته است که باعث تسریع انبساط جهان می‌شود. مدل لامبدا-CDM (ΛCDM) رایج‌ترین مدل کیهان‌شناسی است که انرژی تاریک را به عنوان ثابت کیهان‌شناسی در نظر می‌گیرد."},
  {"question": "تورم کیهانی (Cosmic Inflation) چه مشکلاتی را در مدل استاندارد بیگ بنگ حل می‌کند؟", "answer": "تورم کیهانی یک دوره انبساط بسیار سریع در کسری از ثانیه پس از بیگ بنگ است که مشکلاتی مانند همسانی افق، مسطح بودن جهان و منشاء نوسانات اولیه را حل می‌کند."},
  {"question": "نوسانات اولیه (Primordial Fluctuations) چگونه منجر به تشکیل ساختارهای کیهانی مانند کهکشان‌ها شده‌اند؟", "answer": "این نوسانات که از دوران تورم کیهانی نشأت گرفته‌اند، نواحی با چگالی کمی متفاوت در جهان اولیه ایجاد کردند که به مرور زمان تحت گرانش به ساختارهای بزرگتر مانند کهکشان‌ها و خوشه‌های کهکشانی تبدیل شدند."},
  {"question": "ستاره‌های نوترونی (Neutron Stars) چه ویژگی‌های فیزیکی خارق‌العاده‌ای دارند؟", "answer": "این ستاره‌ها بسیار چگال هستند (یک قاشق چای‌خوری از ماده آن‌ها میلیاردها تن وزن دارد)، دارای میدان مغناطیسی بسیار قوی و سرعت چرخش بالا هستند و از بقایای ابرنواخترها تشکیل می‌شوند."},
  {"question": "سیاه‌چاله‌ها (Black Holes) چگونه تشکیل می‌شوند و چه افقی رویداد (Event Horizon) دارند؟", "answer": "سیاه‌چاله‌ها از فروپاشی گرانشی ستاره‌های بسیار پرجرم تشکیل می‌شوند. افق رویداد مرزی است که فراتر از آن هیچ چیز، حتی نور، نمی‌تواند از گرانش سیاه‌چاله بگریزد."},
  {"question": "تکامل کهکشان‌ها (Galaxy Evolution) چگونه از کهکشان‌های اولیه به کهکشان‌های امروزی منجر شده است؟", "answer": "کهکشان‌ها از طریق ادغام و تعامل با یکدیگر رشد کرده و تکامل یافته‌اند. کهکشان‌های کوتوله به کهکشان‌های بزرگتر پیوسته‌اند و برخوردهای کهکشانی باعث شکل‌گیری ساختارهای مارپیچی و بیضوی شده است."},
  {"question": "منشاء انفجارهای پرتو گاما (Gamma-Ray Bursts) چیست؟", "answer": "این انفجارها به دو دسته اصلی تقسیم می‌شوند: نوع اول ناشی از ادغام ستاره‌های نوترونی یا ستاره نوترونی و سیاه‌چاله، و نوع دوم ناشی از فروپاشی ستاره‌های بسیار پرجرم (ابرنواخترهای پرانرژی)."},
  {"question": "سیارات فراخورشیدی (Exoplanets) چگونه کشف می‌شوند؟ روش‌های اصلی کدامند؟", "answer": "روش‌های اصلی شامل گذر (Transit)، سرعت شعاعی (Radial Velocity)، تصویربرداری مستقیم (Direct Imaging)، و ریزهمگرایی گرانشی (Gravitational Microlensing) هستند."},
  {"question": "چه عواملی برای وجود حیات در سیارات فراخورشیدی ضروری تلقی می‌شوند؟", "answer": "عواملی چون وجود آب مایع، دمای مناسب (در منطقه قابل سکونت ستاره)، اتمسفر پایدار، میدان مغناطیسی محافظ، و وجود عناصر شیمیایی لازم (کربن، هیدروژن، نیتروژن، اکسیژن و غیره) ضروری هستند."},
  {"question": "جستجو برای نشانه‌های حیات فرازمینی (SETI) از چه روش‌هایی استفاده می‌کند؟", "answer": "SETI عمدتاً از رصدخانه‌های رادیویی و تلسکوپ‌های نوری برای جستجوی سیگنال‌های رادیویی یا لیزری مصنوعی از سوی تمدن‌های فرازمینی استفاده می‌کند."},
  {"question": "اتم چه ساختاری دارد و ذرات بنیادی آن کدامند؟", "answer": "اتم از یک هسته مرکزی شامل پروتون‌ها و نوترون‌ها و الکترون‌هایی که در اطراف هسته در اوربیتال‌ها قرار دارند، تشکیل شده است. ذرات بنیادی‌تر شامل کوارک‌ها و لپتون‌ها هستند."},
  {"question": "نیروی هسته‌ای قوی (Strong Nuclear Force) چه نقشی در پایداری هسته اتم دارد؟", "answer": "این نیرو مسئول پیوند دادن کوارک‌ها به یکدیگر برای تشکیل پروتون‌ها و نوترون‌ها، و همچنین پیوند دادن پروتون‌ها و نوترون‌ها به یکدیگر در هسته اتم است و بر نیروهای دافعه الکترواستاتیکی بین پروتون‌ها غلبه می‌کند."},
  {"question": "مکانیک کوانتومی (Quantum Mechanics) چگونه رفتار ذرات در مقیاس اتمی و زیراتمی را توصیف می‌کند؟", "answer": "مکانیک کوانتومی رفتار ذرات را با استفاده از مفاهیمی چون برهم‌نهی (superposition)، درهم‌تنیدگی (entanglement)، و احتمال توصیف می‌کند، که با شهود کلاسیک ما متفاوت است."},
  {"question": "اصل عدم قطعیت هایزنبرگ (Heisenberg Uncertainty Principle) چه محدودیتی برای اندازه‌گیری همزمان ویژگی‌های ذرات اعمال می‌کند؟", "answer": "این اصل بیان می‌کند که نمی‌توان به طور همزمان دقت نامحدودی را برای اندازه‌گیری جفت‌هایی از ویژگی‌های مزدوج یک ذره، مانند موقعیت و تکانه، به دست آورد."},
  {"question": "تونل‌زنی کوانتومی (Quantum Tunneling) چیست و چه کاربردهایی دارد؟", "answer": "تونل‌زنی کوانتومی پدیده‌ای است که در آن یک ذره می‌تواند از یک مانع انرژی عبور کند، حتی اگر انرژی آن کمتر از ارتفاع مانع باشد. این پدیده در میکروسکوپ‌های روبشی تونلی (STM) و واپاشی رادیواکتیو کاربرد دارد."},
  {"question": "اطلاعات کوانتومی (Quantum Information) و محاسبات کوانتومی (Quantum Computing) چگونه کار می‌کنند؟", "answer": "محاسبات کوانتومی از کیوبیت‌ها (qubits) استفاده می‌کند که می‌توانند در حالت ۰، ۱، یا برهم‌نهی از هر دو باشند. این امر امکان انجام محاسبات بسیار پیچیده را به روشی سریع‌تر از کامپیوترهای کلاسیک فراهم می‌کند."},
  {"question": "نوروساینس محاسباتی (Computational Neuroscience) چگونه از مدل‌های ریاضی و کامپیوتری برای فهم مغز استفاده می‌کند؟", "answer": "این رشته با شبیه‌سازی نورون‌ها، شبکه‌های عصبی و سیستم‌های بزرگتر مغزی، فرآیندهای شناختی، یادگیری و اختلالات عصبی را مورد مطالعه قرار می‌دهد."},
  {"question": "پلاستیسیته عصبی (Neural Plasticity) چیست و چگونه مغز قادر به تغییر و انطباق است؟", "answer": "پلاستیسیته عصبی توانایی مغز برای تغییر ساختار و عملکرد خود در پاسخ به تجربه، یادگیری یا آسیب است. این تغییرات شامل ایجاد اتصالات سیناپسی جدید و تقویت یا تضعیف اتصالات موجود است."},
  {"question": "رابط مغز و ماشین (Brain-Machine Interface - BMI) چه تفاوتی با رابط مغز و کامپیوتر (BCI) دارد؟", "answer": "BMI یک اصطلاح کلی‌تر است که شامل BCI می‌شود، اما همچنین می‌تواند شامل دستگاه‌هایی باشد که مغز را تحریک می‌کنند (مانند تحریک عمیق مغز) و نه فقط دریافت سیگنال از مغز."},
  {"question": "سلول‌های بنیادی (Stem Cells) چه ویژگی‌هایی دارند و در تحقیقات پزشکی چه اهمیتی دارند؟", "answer": "سلول‌های بنیادی توانایی تمایز به انواع مختلف سلول‌های تخصصی را دارند و پتانسیل بالایی برای درمان بیماری‌هایی مانند پارکینسون، دیابت و آسیب‌های نخاعی دارند."},
  {"question": "ویروس‌ها چگونه تکثیر می‌شوند و چه نقشی در بیماری‌ها دارند؟", "answer": "ویروس‌ها ذراتی هستند که برای تکثیر به سلول‌های زنده میزبان تکیه می‌کنند. آن‌ها با تزریق ماده ژنتیکی خود به سلول میزبان و استفاده از ماشین‌آلات سلولی، نسخه‌های جدیدی از خود را تولید می‌کنند."},
  {"question": "ژنتیک جمعیت (Population Genetics) چگونه تنوع ژنتیکی در جمعیت‌ها را مطالعه می‌کند؟", "answer": "این رشته با استفاده از مدل‌های ریاضی و داده‌های مولکولی، توزیع و تغییرات فراوانی آلل‌ها (ژن‌ها) در طول زمان را در جمعیت‌ها بررسی می‌کند."},
  {"question": "متاژنومیکس (Metagenomics) چیست و چگونه برای مطالعه میکروبیوم‌ها استفاده می‌شود؟", "answer": "متاژنومیکس مطالعه مستقیم ماده ژنتیکی جمع‌آوری شده از نمونه‌های محیطی (مانند خاک، آب یا نمونه‌های بیولوژیکی) بدون نیاز به کشت میکروب‌ها است. این روش امکان بررسی تنوع و عملکرد جوامع میکروبی را فراهم می‌کند."},
  {"question": "نانوالکترونیک (Nanoelectronics) چه آینده‌ای برای ادوات الکترونیکی رقم می‌زند؟", "answer": "نانوالکترونیک به توسعه ادوات الکترونیکی در مقیاس نانو می‌پردازد که منجر به ساخت تراشه‌های سریع‌تر، کوچک‌تر و کم‌مصرف‌تر، حافظه‌های با ظرفیت بالاتر و سنسورهای حساس‌تر می‌شود."},
  {"question": "رباتیک نرم (Soft Robotics) چه مزایایی نسبت به رباتیک سنتی دارد؟", "answer": "ربات‌های نرم از مواد انعطاف‌پذیر ساخته می‌شوند که امکان حرکت و انطباق‌پذیری بیشتری را فراهم می‌کند. این ربات‌ها برای کاربردهایی مانند جراحی‌های کم‌تهاجمی، تعامل ایمن با انسان و گرفتن اشیاء شکننده مناسب هستند."},
  {"question": "کیهان‌شناسی مشاهده‌ای (Observational Cosmology) چگونه مدل‌های نظری جهان را آزمایش می‌کند؟", "answer": "این رشته با استفاده از داده‌های تلسکوپی (مانند تابش زمینه کیهانی، توزیع کهکشان‌ها و ابرنواخترها) به بررسی ویژگی‌های جهان مانند سن، ترکیب و هندسه آن می‌پردازد و مدل‌های نظری را تأیید یا رد می‌کند."},
  {"question": "منشاء اولیه جهان (Early Universe) چگونه تکامل یافت؟", "answer": "پس از بیگ بنگ، جهان در حال انبساط و خنک شدن بود. در ابتدا ذرات بنیادی، سپس پروتون‌ها و نوترون‌ها، و در نهایت اتم‌های سبک (هیدروژن و هلیوم) تشکیل شدند. تابش زمینه کیهانی بقایای این دوره است."},
  {"question": "نظریه ریسمان چگونه می‌تواند تمام نیروهای بنیادی فیزیک را متحد کند؟", "answer": "نظریه ریسمان تلاش می‌کند تا گرانش را با سایر نیروهای بنیادی (الکترومغناطیس، هسته‌ای قوی و ضعیف) در چارچوب کوانتومی یکپارچه کند، با این فرض که ذرات بنیادی ریسمان‌های ارتعاشی در ابعاد بالاتر هستند."},
  {"question": "تفاوت بین ماده تاریک و انرژی تاریک در چیست؟", "answer": "ماده تاریک اثرات گرانشی دارد و باعث تجمع ماده می‌شود، در حالی که انرژی تاریک یک نیروی دافعه است که باعث تسریع انبساط جهان می‌شود. هر دو ناشناخته هستند و بخش عمده‌ای از جرم-انرژی جهان را تشکیل می‌دهند."},
  {"question": "اگر یک سیاه‌چاله را زیاد به آن نزدیک شویم چه اتفاقی می‌افتد؟ (اثر اسپاگتیزاسیون)", "answer": "نیروی کشندی (tidal force) بسیار قوی سیاه‌چاله، بدن را مانند اسپاگتی در امتداد محور شعاعی می‌کشد و آن را از هم باز می‌کند. این پدیده به 'اثر اسپاگتیزاسیون' معروف است."},
  {"question": "چه نوع ستاره‌هایی ابرنواختر (Supernova) ایجاد می‌کنند؟", "answer": "ابرنواخترها عمدتاً از دو نوع ستاره حاصل می‌شوند: ستاره‌های پرجرم (بیش از ۸ برابر جرم خورشید) که در پایان عمر خود فرو می‌پاشند، و کوتوله‌های سفید در سیستم‌های دوتایی که جرم کافی از ستاره همدم خود دریافت می‌کنند و دچار انفجار ترمونوکلئار می‌شوند."},
  {"question": "پالسارها (Pulsars) چه هستند و چگونه کشف شدند؟", "answer": "پالسارها ستاره‌های نوترونی چرخان بسیار سریعی هستند که پرتوهای الکترومغناطیسی را از قطب‌های مغناطیسی خود ساطع می‌کنند. این پرتوها به صورت دوره‌ای با چرخش ستاره، مانند نور یک فانوس دریایی، به سمت زمین می‌آیند و به عنوان پالس‌های رادیویی کشف شدند."},
  {"question": "انبساط جهان چگونه اندازه‌گیری می‌شود؟ (ثابت هابل)", "answer": "با اندازه‌گیری فاصله کهکشان‌ها (با استفاده از شمع‌های استاندارد مانند نواخترهای نوع Ia) و سرعت دور شدن آن‌ها (با استفاده از جابجایی به سرخ)، می‌توان نرخ انبساط جهان را که با ثابت هابل (H₀) بیان می‌شود، تعیین کرد."},
  {"question": "تلسکوپ فضایی جیمز وب (JWST) چه اکتشافات جدیدی در نجوم امکان‌پذیر کرده است؟", "answer": "JWST با توانایی رصد در طول موج‌های فروسرخ، امکان مشاهده اولین ستارگان و کهکشان‌ها، مطالعه دقیق‌تر جو سیارات فراخورشیدی، و تصویربرداری از مناطق ستاره‌زایی را فراهم کرده است."},
  {"question": "آیا امکان سفر سریع‌تر از نور وجود دارد؟", "answer": "طبق نظریه نسبیت خاص اینشتین، هیچ جسمی که دارای جرم باشد نمی‌تواند به سرعت نور برسد یا از آن فراتر رود. با این حال، ایده‌هایی مانند پیچش فضا-زمان (Warp Drive) در قلمرو نظریه باقی مانده‌اند."},
  {"question": "چه نشانه‌هایی از حیات میکروبی در مریخ جستجو می‌شود؟", "answer": "دانشمندان به دنبال نشانه‌هایی از حیات گذشته یا حال، مانند مولکول‌های آلی خاص، فسیل‌های میکروبی، و گازهایی مانند متان در جو مریخ هستند که می‌توانند توسط فعالیت‌های زیستی تولید شده باشند."},
  {"question": "اتصال کوانتومی (Quantum Entanglement) چیست و چرا 'عمل شبح‌وار در دوردست' نامیده می‌شود؟", "answer": "اتصال کوانتومی حالتی است که در آن دو یا چند ذره به گونه‌ای به هم مرتبط می‌شوند که اندازه‌گیری وضعیت یک ذره، بلافاصله وضعیت ذره دیگر را، صرف نظر از فاصله، مشخص می‌کند. این پدیده به دلیل تأثیر آنی و غیرمحلی، توسط اینشتین 'عمل شبح‌وار در دوردست' نامیده شد."},
  {"question": "چگونه می‌توانیم میدان مغناطیسی زمین را مدل‌سازی کنیم؟", "answer": "میدان مغناطیسی زمین عمدتاً توسط جریان‌های الکتریکی در هسته بیرونی مایع آن تولید می‌شود (دینامو). مدل‌سازی آن شامل استفاده از معادلات ماکسول و داده‌های مغناطیس‌سنجی از سطح زمین و ماهواره‌ها است."},
  {"question": "تاثیرFIELDS (Fields) بر سرعت نور در نسبیت عام چیست؟", "answer": "در نسبیت عام،FIELDS (میدان‌ها) ساختار فضا-زمان را خمیده می‌کنند، که این انحنا بر مسیر حرکت نور تأثیر می‌گذارد. این پدیده به عنوان همگرایی گرانشی (gravitational lensing) مشاهده می‌شود و باعث می‌شود نور در اطراف اجرام پرجرم منحرف شود."},
  {"question": "تکامل ستارگان چگونه بر عناصر شیمیایی موجود در جهان تأثیر می‌گذارد؟", "answer": "عناصر سبک‌تر در ستاره‌های اولیه (مانند هیدروژن و هلیوم) از طریق همجوشی هسته‌ای در هسته ستاره‌ها به عناصر سنگین‌تر تبدیل می‌شوند. عناصر سنگین‌تر از آهن عمدتاً در انفجار ابرنواخترها تولید می‌شوند."},
  {"question": "آیا امکان وجود حیات بر اساس شیمی سیلیکون به جای کربن وجود دارد؟", "answer": "هرچند کربن به دلیل توانایی بالای خود در تشکیل پیوندهای پایدار و متنوع، بهترین کاندید برای حیات است، اما از نظر تئوری، سیلیکون نیز می‌تواند در شرایط خاص (مانند دماهای بسیار بالا و حلال‌های غیرآبی) پایه‌های مولکول‌های پیچیده را تشکیل دهد، هرچند این امر بسیار کمتر محتمل است."},
  {"question": "خورشید ما در کدام کهکشان قرار دارد؟", "answer": "راه شیری (Milky Way)"},
  {"question": "نزدیک‌ترین ستاره به زمین پس از خورشید چیست؟", "answer": "پروکسیما قنطورس (Proxima Centauri)"},
  {"question": "به چه دلیل رنگ آسمان در طول روز آبی است؟", "answer": "پراکندگی نور خورشید توسط مولکول‌های هوا (پراکندگی ریلی)"},
  {"question": "بزرگترین سیاره در منظومه شمسی ما کدام است؟", "answer": "مشتری (Jupiter)"},
  {"question": "اولین فضانورد کی بود و به کجا سفر کرد؟", "answer": "یوری گاگارین، اولین انسان در فضا (مدار زمین)"},
  {"question": "سیاهچاله چیست؟", "answer": "ناحیه‌ای از فضا-زمان که گرانش آنقدر قوی است که هیچ چیز، حتی نور، نمی‌تواند از آن فرار کند."},
  {"question": "چرا ماه در آسمان می‌درخشد؟", "answer": "نور خورشید که به سطح ماه می‌تابد و بازتاب می‌شود."},
  {"question": "کهکشان چیست؟", "answer": "یک مجموعه عظیم از ستارگان، گاز، غبار و ماده تاریک که توسط گرانش کنار هم نگه داشته شده‌اند."},
  {"question": "اولین ماهواره‌ای که به فضا پرتاب شد چه نام داشت؟", "answer": "اسپوتنیک ۱ (Sputnik 1)"},
  {"question": "عمر تقریبی منظومه شمسی ما چقدر است؟", "answer": "حدود ۴.۶ میلیارد سال."},
  {"question": "چهارمین سیاره از خورشید کدام است؟", "answer": "مریخ (Mars)"},
  {"question": "آیا امکان وجود حیات در سیارات دیگر وجود دارد؟", "answer": "این یک سوال فعال در علم است و شواهد قطعی هنوز کشف نشده، اما احتمالات زیادی وجود دارد."},
  {"question": "تلسکوپ چیست و چه کاربردی دارد؟", "answer": "ابزاری برای مشاهده اجرام دوردست با بزرگنمایی تصویر آن‌ها؛ در نجوم برای دیدن ستارگان، سیارات و کهکشان‌ها استفاده می‌شود."},
  {"question": "ستاره دنباله‌دار چیست؟", "answer": "یک جرم آسمانی متشکل از یخ، غبار و سنگ که هنگام نزدیک شدن به خورشید دم درخشانی ایجاد می‌کند."},
  {"question": "پدیده‌ی شفق قطبی (Aurora) چگونه رخ می‌دهد؟", "answer": "برخورد ذرات باردار خورشیدی با میدان مغناطیسی و اتمسفر زمین."},
  {"question": "چرا سیارات به دور خورشید می‌چرخند؟", "answer": "به دلیل نیروی گرانش خورشید."},
  {"question": "منظور از \"سال نوری\" (Light-year) چیست؟", "answer": "مسافتی که نور در یک سال طی می‌کند؛ واحد اندازه‌گیری فاصله در نجوم."},
  {"question": "اولین مأموریت فضایی سرنشین‌دار به ماه چه نام داشت؟", "answer": "آپولو ۱۱ (Apollo 11)"},
  {"question": "چرا ما همیشه یک سمت ماه را می‌بینیم؟", "answer": "به دلیل قفل گرانشی (Tidal Locking)؛ ماه با سرعت چرخش خود به دور زمین، به دور خود نیز می‌چرخد."},
  {"question": "سحابی (Nebula) چیست؟", "answer": "ابری از غبار و گاز در فضا، اغلب محل تولد ستارگان جدید."},
  {"question": "منظور از \"گسترش جهان\" (Expansion of the Universe) چیست؟", "answer": "اینکه فواصل بین کهکشان‌ها در طول زمان در حال افزایش است."},
  {"question": "سریع‌ترین سیاره منظومه شمسی کدام است؟", "answer": "عطارد (Mercury)"},
  {"question": "چه عواملی باعث ایجاد جزر و مد در زمین می‌شوند؟", "answer": "عمدتاً نیروی گرانش ماه و خورشید."},
  {"question": "چند سیاره در منظومه شمسی ما وجود دارد؟", "answer": "هشت سیاره (عطارد، زهره، زمین، مریخ، مشتری، زحل، اورانوس، نپتون)."},
  {"question": "کهکشان آندرومدا (Andromeda) چیست؟", "answer": "نزدیک‌ترین کهکشان مارپیچی بزرگ به کهکشان راه شیری ما."},
  {"question": "مغز انسان از چه بخش‌های اصلی تشکیل شده است؟", "answer": "مخ (Cerebrum)، مخچه (Cerebellum)، و ساقه مغز (Brainstem)."},
  {"question": "واحد اصلی تشکیل دهنده سیستم عصبی چیست؟", "answer": "نورون (Neuron) یا سلول عصبی."},
  {"question": "وظیفه اصلی نورون‌ها چیست؟", "answer": "انتقال اطلاعات از طریق سیگنال‌های الکتریکی و شیمیایی."},
  {"question": "سیناپس (Synapse) چیست؟", "answer": "فضای کوچکی بین دو نورون که در آن پیام‌های عصبی منتقل می‌شوند."},
  {"question": "انتقال‌دهنده‌های عصبی (Neurotransmitters) چه نقشی دارند؟", "answer": "مواد شیمیایی که پیام‌ها را از یک نورون به نورون دیگر منتقل می‌کنند (مانند دوپامین، سروتونین)."},
  {"question": "قشر مغز (Cerebral Cortex) مسئول چه عملکردهایی است؟", "answer": "تفکر، حافظه، زبان، آگاهی و پردازش اطلاعات حسی."},
  {"question": "نقش هیپوکامپ (Hippocampus) در مغز چیست؟", "answer": "نقش کلیدی در تشکیل حافظه جدید."},
  {"question": "آمیگدال (Amygdala) چه کاری انجام می‌دهد؟", "answer": "پردازش هیجانات، به ویژه ترس."},
  {"question": "مخچه (Cerebellum) عمدتاً مسئول چه چیزی است؟", "answer": "تنظیم حرکات، تعادل و وضعیت بدن."},
  {"question": "ساقه مغز (Brainstem) چه عملکردهای حیاتی را کنترل می‌کند؟", "answer": "تنفس، ضربان قلب، فشار خون و هوشیاری."},
  {"question": "آیا مغز انسان قادر به تولید نورون‌های جدید پس از تولد است؟", "answer": "بله، در برخی نواحی مغز (مانند هیپوکامپ) پدیده‌ای به نام نوروژنز (Neurogenesis) رخ می‌دهد."},
  {"question": "اهمیت خواب برای مغز چیست؟", "answer": "پاکسازی مواد زائد، تثبیت حافظه و ترمیم سلول‌ها."},
  {"question": "چه چیزی باعث می‌شود ما درد را احساس کنیم؟", "answer": "فعال شدن گیرنده‌های درد (Nociceptors) و ارسال سیگنال به مغز از طریق مسیرهای عصبی."},
  {"question": "سیستم عصبی محیطی (Peripheral Nervous System) شامل چه بخش‌هایی است؟", "answer": "تمام اعصاب خارج از مغز و نخاع؛ شامل اعصاب حسی و حرکتی."},
  {"question": "نقش نخاع (Spinal Cord) چیست؟", "answer": "انتقال پیام‌های عصبی بین مغز و سایر نقاط بدن و همچنین کنترل برخی رفلکس‌ها."},
  {"question": "منظور از \"پلاستیسیته مغزی\" (Neuroplasticity) چیست؟", "answer": "توانایی مغز برای تغییر و سازماندهی مجدد خود با ایجاد اتصالات عصبی جدید در طول زندگی."},
  {"question": "چگونه مغز اطلاعات بصری را پردازش می‌کند؟", "answer": "از طریق مسیرهای عصبی پیچیده که از چشم به قشر بینایی در مغز می‌روند."},
  {"question": "چه عواملی می‌توانند بر عملکرد مغز تأثیر منفی بگذارند؟", "answer": "آسیب‌های فیزیکی، سموم، بیماری‌ها، استرس مزمن، کمبود خواب و تغذیه نامناسب."},
  {"question": "آیا احساسات در مغز پردازش می‌شوند؟", "answer": "بله، نواحی مختلفی مانند آمیگدال، قشر پیشانی و سیستم لیمبیک در پردازش هیجانات نقش دارند."},
  {"question": "نقش لوب پیشانی (Frontal Lobe) چیست؟", "answer": "برنامه‌ریزی، تصمیم‌گیری، حل مسئله، شخصیت و کنترل رفتاری."},
  {"question": "لوب گیجگاهی (Temporal Lobe) مسئول چه عملکردهایی است؟", "answer": "پردازش شنوایی، حافظه و درک زبان."},
  {"question": "لوب آهیانه (Parietal Lobe) چه وظایفی دارد؟", "answer": "پردازش اطلاعات حسی مانند لامسه، دما، درد و فشار؛ همچنین جهت‌یابی فضایی."},
  {"question": "لوب پس سری (Occipital Lobe) عمدتاً برای چه کاری استفاده می‌شود؟", "answer": "پردازش اطلاعات بصری (بینایی)."},
  {"question": "آیا مغز انسان می‌تواند همزمان چندین کار را انجام دهد؟", "answer": "مغز می‌تواند بین وظایف مختلف جابجا شود، اما تمرکز عمیق روی چند کار پیچیده همزمان دشوار است."},
  {"question": "چه چیزی باعث \"فراموشی\" می‌شود؟", "answer": "عوامل متعددی مانند عدم تثبیت حافظه، تداخل اطلاعات، عدم بازیابی مؤثر یا آسیب به ساختارهای حافظه در مغز."},
  {"question": "جدول تناوبی عناصر چیست؟", "answer": "یک نمایش جدولی از عناصر شیمیایی که بر اساس خواص فیزیکی و شیمیایی آن‌ها مرتب شده‌اند."},
  {"question": "چه کسی جدول تناوبی را اختراع کرد؟", "answer": "دیمیتری مندلیف (Dmitri Mendeleev) در سال ۱۸۶۹."},
  {"question": "عناصر چگونه در جدول تناوبی مرتب شده‌اند؟", "answer": "بر اساس عدد اتمی (تعداد پروتون‌ها)، پیکربندی الکترون‌ها و خواص شیمیایی تکرارشونده آن‌ها."},
  {"question": "منظور از \"عدد اتمی\" (Atomic Number) چیست؟", "answer": "تعداد پروتون‌های موجود در هسته یک اتم؛ این عدد منحصر به فرد هر عنصر است."},
  {"question": "چرا عناصر با خواص مشابه در یک ستون (گروه) قرار می‌گیرند؟", "answer": "زیرا آن‌ها تعداد الکترون‌های لایه ظرفیت یکسانی دارند که تعیین کننده رفتار شیمیایی آن‌هاست."},
  {"question": "ستون‌های عمودی در جدول تناوبی چه نامیده می‌شوند؟", "answer": "گروه‌ها (Groups)."},
  {"question": "ردیف‌های افقی در جدول تناوبی چه نامیده می‌شوند؟", "answer": "دوره‌ها (Periods)."},
  {"question": "اولین دوره جدول تناوبی چند عنصر دارد؟", "answer": "دو عنصر: هیدروژن (H) و هلیوم (He)."},
  {"question": "عناصر گروه ۱ جدول تناوبی چه نام دارند؟", "answer": "فلزات قلیایی (Alkali Metals)."},
  {"question": "عناصر گروه ۱۷ جدول تناوبی چه نام دارند؟", "answer": "هالوژن‌ها (Halogens)."},
  {"question": "عناصر گروه ۱۸ جدول تناوبی چه نام دارند؟", "answer": "گازهای نجیب (Noble Gases) یا گازهای بی‌اثر."},
  {"question": "چرا گازهای نجیب معمولاً واکنش‌پذیر نیستند؟", "answer": "زیرا لایه الکترونی بیرونی آن‌ها پر است و به پایداری بالایی دست یافته‌اند."},
  {"question": "منظور از \"فلز\" (Metal) چیست؟", "answer": "عناصری که معمولاً رسانای خوب گرما و الکتریسیته هستند، قابلیت چکش‌خواری دارند و تمایل به از دست دادن الکترون دارند."},
  {"question": "منظور از \"نافلز\" (Nonmetal) چیست؟", "answer": "عناصر که معمولاً رسانای ضعیف هستند و تمایل به گرفتن الکترون دارند."},
  {"question": "عناصر نیمه‌رسانا (Metalloids) چه ویژگی‌هایی دارند؟", "answer": "خواصی بین فلزات و نافلزات دارند و می‌توانند در شرایط خاص رسانا باشند."},
  {"question": "چرا جدول تناوبی \"تناوبی\" نامیده می‌شود؟", "answer": "زیرا خواص شیمیایی عناصر به صورت دوره‌ای با افزایش عدد اتمی تکرار می‌شوند."},
  {"question": "اگر عناصر را بر اساس جرم اتمی مرتب می‌کردیم، چه مشکلی پیش می‌آمد؟", "answer": "برخی عناصر خواص شیمیایی نادرستی پیدا می‌کردند؛ عدد اتمی اساس بهتری برای دسته‌بندی است."},
  {"question": "نماد شیمیایی یک عنصر چیست؟", "answer": "یک یا دو حرفی که نمایانگر نام آن عنصر است (مثلاً H برای هیدروژن، O برای اکسیژن)."},
  {"question": "اهمیت عدد اتمی در شناسایی یک عنصر چیست؟", "answer": "عدد اتمی منحصر به فرد است و هویت اصلی یک عنصر را مشخص می‌کند."},
  {"question": "چرا هیدروژن (H) گاهی در گروه ۱ و گاهی در گروه ۱۷ قرار داده می‌شود؟", "answer": "به دلیل خواص منحصر به فردش؛ هیدروژن می‌تواند یک الکترون را از دست بدهد (مانند فلزات قلیایی) یا یک الکترون بگیرد (مانند هالوژن‌ها)."},
  {"question": "منظور از \"دوره\" (Period) در جدول تناوبی چیست؟", "answer": "هر ردیف افقی که نشان‌دهنده تعداد لایه‌های الکترونی اصلی در اتم است."},
  {"question": "چرا با افزایش عدد اتمی در یک دوره، شعاع اتمی کاهش می‌یابد؟", "answer": "به دلیل افزایش بار هسته‌ای مؤثر که الکترون‌ها را بیشتر به سمت هسته می‌کشد."},
  {"question": "چرا با افزایش عدد اتمی در یک گروه، شعاع اتمی افزایش می‌یابد؟", "answer": "به دلیل اضافه شدن لایه‌های الکترونی جدید که اتم را بزرگتر می‌کنند."},
  {"question": "چرا جدول تناوبی یک \"قانون\" نیست، بلکه یک \"دسته‌بندی\" است؟", "answer": "چون بر اساس مشاهدات و خواص عناصر ساخته شده تا روابط بین آن‌ها را نشان دهد، نه یک قانون فیزیکی بنیادی."},
  {"question": "نقش الکترون‌های لایه ظرفیت چیست؟", "answer": "این الکترون‌ها در واکنش‌های شیمیایی شرکت می‌کنند و خواص شیمیایی عنصر را تعیین می‌نمایند."},
  {"question": "آیا عناصر مصنوعی (ساخته دست بشر) در جدول تناوبی وجود دارند؟", "answer": "بله، عناصری با عدد اتمی بالا که در آزمایشگاه‌ها ساخته شده‌اند و معمولاً ناپایدار هستند."},
  {"question": "منظور از \"تکامل\" جدول تناوبی چیست؟", "answer": "کشف عناصر جدید و درک بهتر روابط بین آن‌ها که به تکمیل و اصلاح جدول منجر شده است."},
  {"question": "چرا عناصر واسطه (Transition Metals) در بلوک d جدول قرار دارند؟", "answer": "به دلیل پر شدن اوربیتال‌های d که مسئول خواص خاص این عناصر است."},
  {"question": "آیا همه عناصر در جدول تناوبی به طور طبیعی یافت می‌شوند؟", "answer": "خیر، بسیاری از عناصر سنگین‌تر (با عدد اتمی بالا) مصنوعی هستند و در طبیعت یافت نمی‌شوند."},
  {"question": "چرا جدول تناوبی ابزار مهمی برای شیمیدانان است؟", "answer": "به آن‌ها کمک می‌کند تا خواص عناصر را پیش‌بینی کنند، واکنش‌های شیمیایی را درک کنند و مواد جدیدی را طراحی کنند."},
  {"question": "عنصر پس از قلع (Sn) در جدول تناوبی چیست؟", "answer": "آنتی‌مون (Antimony - Sb) با عدد اتمی ۵۱."},
  {"question": "آنتی‌مون (Sb) در کدام گروه و دوره قرار دارد؟", "answer": "گروه ۱۵، دوره ۵."},
  {"question": "چه خواصی آنتی‌مون را در دسته شبه‌فلزها قرار می‌دهد؟", "answer": "رسانایی الکتریکی و گرمایی متوسط، و قابلیت تشکیل ترکیبات در حالت‌های اکسیداسیونی مختلف."},
  {"question": "عنصر بعدی، تلوریم (Te)، چه جایگاهی در جدول دارد؟", "answer": "عدد اتمی ۵۲، گروه ۱۶، دوره ۵؛ همچنین یک شبه‌فلز."},
  {"question": "چرا تلوریم (Te) با وجود قرار گرفتن در گروه ۱۶ (کالکوژن‌ها) خواص شبه‌فلزی دارد؟", "answer": "افزایش عدد اتمی در گروه باعث کاهش خاصیت نافلزی و افزایش خاصیت فلزی می‌شود."},
  {"question": "ید (I) با عدد اتمی ۵۳، چه نوع عنصری است؟", "answer": "یک هالوژن (گروه ۱۷، دوره ۵)، یک نافلز."},
  {"question": "یُد (I) چه کاربردهای مهمی دارد؟", "answer": "ضدعفونی‌کننده، در مکمل‌های غذایی برای سلامت تیروئید، و در مواد کنتراست برای تصویربرداری پزشکی."},
  {"question": "عنصر بعدی، زنون (Xe)، چیست؟", "answer": "یک گاز نجیب (گروه ۱۸، دوره ۵)، عنصری بی‌اثر و گازی در دمای اتاق."},
  {"question": "کاربردهای زنون (Xe) چیست؟", "answer": "در لامپ‌های پرنور (مانند چراغ خودرو)، لیزرها، و به عنوان بیهوش‌کننده."},
  {"question": "اولین عنصر دوره ۶، سزیم (Cs)، با عدد اتمی ۵۵، چه ویژگی دارد؟", "answer": "یک فلز قلیایی (گروه ۱، دوره ۶)، بسیار واکنش‌پذیر و نرم."},
  {"question": "چرا سزیم (Cs) از روبیدیم (Rb) واکنش‌پذیرتر است؟", "answer": "به دلیل شعاع اتمی بزرگتر و انرژی یونیزاسیون کمتر، راحت‌تر الکترون از دست می‌دهد."},
  {"question": "باریم (Ba) با عدد اتمی ۵۶، چه نوع عنصری است؟", "answer": "فلز قلیایی خاکی (گروه ۲، دوره ۶)."},
  {"question": "عناصر لانتانیدها (Lanthanides) از چه عدد اتمی شروع می‌شوند؟", "answer": "از لانتانوم (La) با عدد اتمی ۵۷ شروع شده و تا ایتربیم (Yb) با عدد اتمی ۷۱ ادامه دارند."},
  {"question": "چرا لانتانیدها در ردیف جداگانه‌ای پایین جدول قرار گرفته‌اند؟", "answer": "برای حفظ ساختار فشرده جدول و جلوگیری از طولانی شدن بیش از حد آن؛ این عناصر خواص مشابهی دارند."},
  {"question": "لوتسیوم (Lu) با عدد اتمی ۷۱، اولین عنصر پس از لانتانیدهاست. در کدام گروه است؟", "answer": "گروه ۳، دوره ۶ (پایان سری لانتانیدها)."},
  {"question": "هافنیوم (Hf) با عدد اتمی ۷۲، اولین عنصر در بلوک d (فلزات واسطه) دوره ۶ است. خواص آن چیست؟", "answer": "یک فلز مقاوم در برابر خوردگی، با نقطه ذوب بالا."},
  {"question": "تانتال (Ta) با عدد اتمی ۷۳، چه کاربردهایی دارد؟", "answer": "در ساخت فولادهای آلیاژی، قطعات الکترونیکی (مانند خازن‌ها) و ایمپلنت‌های پزشکی به دلیل مقاومت بالا در برابر خوردگی."},
  {"question": "تنگستن (W) با عدد اتمی ۷۴، به چه معروف است؟", "answer": "به دلیل نقطه ذوب بسیار بالا (بالاترین در بین فلزات)، در ساخت رشته لامپ‌ها، ابزارهای برش و الکترودها استفاده می‌شود."},
  {"question": "رنیوم (Re) با عدد اتمی ۷۵، چه خواصی دارد؟", "answer": "یکی از چگال‌ترین و با نقطه ذوب بالا؛ در آلیاژهای توربین‌های جت و کاتالیزورها کاربرد دارد."},
  {"question": "اوسمیوم (Os) با عدد اتمی ۷۶، شناخته شده‌ترین خاصیتش چیست؟", "answer": "چگال‌ترین عنصر طبیعی شناخته شده، بسیار سخت و شکننده؛ در آلیاژها برای افزایش سختی و مقاومت سایشی کاربرد دارد."},
  {"question": "ایریدیوم (Ir) با عدد اتمی ۷۷، چه ویژگی دارد؟", "answer": "بسیار مقاوم در برابر خوردگی، حتی در دماهای بالا؛ در ساخت الکترودها، اجزای موتور و جواهرات کاربرد دارد."},
  {"question": "پلاتین (Pt) با عدد اتمی ۷۸، به چه معروف است؟", "answer": "به دلیل ارزش بالا، مقاومت در برابر خوردگی و خواص کاتالیزوری؛ در جواهرات، کاتالیزور خودرو و تجهیزات آزمایشگاهی."},
  {"question": "طلا (Au) با عدد اتمی ۷۹، چه خواصی دارد؟", "answer": "فلزی گرانبها، چکش‌خوار، بسیار رسانا و مقاوم در برابر خوردگی؛ در جواهرات، الکترونیک و دندانپزشکی."},
  {"question": "جیوه (Hg) با عدد اتمی ۸۰، چه ویژگی منحصربه‌فردی دارد؟", "answer": "تنها فلزی که در دمای اتاق مایع است؛ در دماسنج‌ها، فشارسنج‌ها و ترموستات‌ها (کاربرد آن محدود شده است)."},
  {"question": "تالیم (Tl) با عدد اتمی ۸۱، در کدام دسته قرار می‌گیرد؟", "answer": "فلز سنگین (گروه ۱۳، دوره ۶)، بسیار سمی."},
  {"question": "سرب (Pb) با عدد اتمی ۸۲، چه خواصی دارد؟", "answer": "فلزی نرم، چگال و سمی؛ در باتری‌ها، محافظت در برابر اشعه و لحیم‌کاری (کاربرد آن محدود شده است)."},
  {"question": "بیسموت (Bi) با عدد اتمی ۸۳، چه جایگاهی دارد؟", "answer": "عنصر پایدار انتهایی در گروه ۱۵؛ بسیاری از ترکیبات آن سمیت کمتری نسبت به آنتی‌مون دارند و در داروها کاربرد دارند."},
  {"question": "پولونیوم (Po) با عدد اتمی ۸۴، چه ویژگی دارد؟", "answer": "یک نافلز رادیواکتیو؛ بسیار سمی و تنها در مقادیر کم یافت می‌شود."},
  {"question": "استاتین (At) با عدد اتمی ۸۵، چیست؟", "answer": "یک هالوژن رادیواکتیو؛ نادرترین عنصر طبیعی پایدار (و عمدتاً مصنوعی)."},
  {"question": "رادون (Rn) با عدد اتمی ۸۶، چیست؟", "answer": "یک گاز نجیب رادیواکتیو (گروه ۱۸، دوره ۶)؛ محصول واپاشی رادیوم و می‌تواند در ساختمان‌ها تجمع یابد."},
  {"question": "فرانسیم (Fr) با عدد اتمی ۸۷، اولین عنصر دوره هفتم چیست؟", "answer": "یک فلز قلیایی (گروه ۱، دوره ۷)، بسیار رادیواکتیو و نادر."},
  {"question": "رادیوم (Ra) با عدد اتمی ۸۸، چه نوع عنصری است؟", "answer": "یک فلز قلیایی خاکی (گروه ۲، دوره ۷)، رادیواکتیو."},
  {"question": "چه زمانی اکتینیدها (Actinides) در جدول تناوبی شروع می‌شوند؟", "answer": "با اکتینیم (Ac) با عدد اتمی ۸۹ (گروه ۳، دوره ۷)."},
  {"question": "چرا اکتینیدها در ردیف جداگانه زیر لانتانیدها قرار دارند؟", "answer": "مانند لانتانیدها، برای حفظ فشردگی جدول و به دلیل داشتن خواص شیمیایی مشابه یکدیگر (پر شدن اوربیتال‌های f)."},
  {"question": "توریم (Th) با عدد اتمی ۹۰، چه ویژگی دارد؟", "answer": "یک فلز رادیواکتیو که در طبیعت یافت می‌شود و در واکنش‌های هسته‌ای کاربرد دارد."},
  {"question": "پلوتونیوم (Pu) با عدد اتمی ۹۴، چقدر مهم است؟", "answer": "یک عنصر رادیواکتیو مصنوعی که در سلاح‌های هسته‌ای و سوخت راکتورهای هسته‌ای کاربرد دارد."},
  {"question": "آمرسیوم (Am) با عدد اتمی ۹۵، در کجا یافت می‌شود؟", "answer": "در دتکتورهای دود (به مقدار بسیار کم و ایمن) و به عنوان منبع پرتو گاما در کاربردهای صنعتی."},
  {"question": "کوریوم (Cm) با عدد اتمی ۹۶، چه کاربردی دارد؟", "answer": "به عنوان منبع انرژی در مولدهای ترموالکتریک رادیوایزوتوپی (RTGs) برای فضاپیماها."},
  {"question": "برکلیوم (Bk) با عدد اتمی ۹۷، چگونه تولید می‌شود؟", "answer": "به صورت مصنوعی در راکتورهای هسته‌ای یا شتاب‌دهنده‌ها، بسیار رادیواکتیو."},
  {"question": "کالیفرنیوم (Cf) با عدد اتمی ۹۸، چه خواصی دارد؟", "answer": "بسیار رادیواکتیو؛ در برخی دستگاه‌های سنجش چگالی نفت و به عنوان منبع نوترون کاربرد دارد."},
  {"question": "اینشتینیم (Es) با عدد اتمی ۹۹، به افتخار چه کسی نامگذاری شده است؟", "answer": "آلبرت انیشتین."},
  {"question": "فرمیوم (Fm) با عدد اتمی ۱۰۰، به افتخار چه کسی نامگذاری شده است؟", "answer": "انریکو فرمی."},
  {"question": "مندلویم (Md) با عدد اتمی ۱۰۱، و نوبلیوم (No) با عدد اتمی ۱۰۰، چه ویژگی مشترکی دارند؟", "answer": "عناصر مصنوعی فوق سنگین با نیمه‌عمر کوتاه."},
  {"question": "لارنسیم (Lr) با عدد اتمی ۱۰۳، اولین عنصر دوره هفتم در بلوک d است. این بدان معناست که ...", "answer": "... اوربیتال‌های f آن پر شده و اوربیتال‌های d آن در حال پر شدن هستند."},
  {"question": "رادرفوردیوم (Rf) با عدد اتمی ۱۰۴، اولین عنصر فوق سنگین مصنوعی کامل است. چه نوع عنصری است؟", "answer": "یک فلز واسطه (بلوک d، دوره ۷)."},
  {"question": "دوبنیوم (Db) با عدد اتمی ۱۰۵، چه خواصی دارد؟", "answer": "عنصر مصنوعی فوق سنگین، خواص شیمیایی آن تا حد زیادی نظری است."},
  {"question": "سیبورگیم (Sg) با عدد اتمی ۱۰۶، به افتخار چه کسی نامگذاری شده است؟", "answer": "گلن سیبورگ (Glenn Seaborg)، شیمیدان هسته‌ای برجسته."},
  {"question": "بوریم (Bh) با عدد اتمی ۱۰۷، چه ویژگی دارد؟", "answer": "عنصر مصنوعی فوق سنگین، با نیمه‌عمر بسیار کوتاه، خواص آن پیش‌بینی شده است."},
  {"question": "هاسیم (Hs) با عدد اتمی ۱۰۸، در کدام گروه قرار دارد؟", "answer": "گروه ۱۰ (مانند نیکل، پالادیوم، پلاتین)."},
  {"question": "مایتنریم (Mt) با عدد اتمی ۱۰۹، چه نوع عنصری است؟", "answer": "یک فلز واسطه مصنوعی فوق سنگین."},
  {"question": "دارمشتاتیوم (Ds) با عدد اتمی ۱۱۰، چه خواصی دارد؟", "answer": "عنصر مصنوعی فوق سنگین، پیش‌بینی می‌شود خواص آن شبیه به جیوه (Hg) باشد."},
  {"question": "رونتگنیوم (Rg) با عدد اتمی ۱۱۱، در کدام گروه است؟", "answer": "گروه ۱۱ (مانند مس، نقره، طلا)."},
  {"question": "کوپرنیسیم (Cn) با عدد اتمی ۱۱۲، چه ویژگی دارد؟", "answer": "عنصر مصنوعی فوق سنگین؛ تصور می‌شود خواص آن شبیه به عنصر دوره ۶، کوپرتینسیوم (Cu) باشد."},
  {"question": "نیهونیوم (Nh) با عدد اتمی ۱۱۳، اولین عنصر در بلوک p دوره ۷ چیست؟", "answer": "یک شبه‌فلز یا فلز ضعیف؛ خواص آن هنوز به طور کامل تایید نشده است."},
  {"question": "فلروویم (Fl) با عدد اتمی ۱۱۴، چه نوع عنصری است؟", "answer": "یک فلز ضعیف یا شبه‌فلز (گروه ۱۴، دوره ۷)."},
  {"question": "مسکویوم (Mc) با عدد اتمی ۱۱۵، چه خواصی دارد؟", "answer": "عنصر مصنوعی؛ پیش‌بینی می‌شود خواص آن شبیه بیسموت (Bi) باشد."},
  {"question": "لیورموریوم (Lv) با عدد اتمی ۱۱۶، چه نوع عنصری است؟", "answer": "یک فلز نافلزی یا شبه‌فلز (گروه ۱۶، دوره ۷)."},
  {"question": "تِنِسین (Ts) با عدد اتمی ۱۱۷، چیست؟", "answer": "یک هالوژن مصنوعی (گروه ۱۷، دوره ۷)؛ انتظار می‌رود خواص شیمیایی آن با هالوژن‌های دیگر متفاوت باشد."},
  {"question": "اوگانسون (Og) با عدد اتمی ۱۱۸، آخرین عنصر شناخته شده در جدول تناوبی است. چه نوع عنصری است؟", "answer": "یک گاز نجیب (گروه ۱۸، دوره ۷)؛ اولین عنصر دوره هفتم که در بلوک p قرار دارد."},
  {"question": "چرا عناصر فوق سنگین (Superheavy Elements) به سختی تولید و مطالعه می‌شوند؟", "answer": "به دلیل نیمه‌عمر بسیار کوتاه، نیاز به تجهیزات پیشرفته شتاب‌دهنده ذرات و تولید در مقیاس اتمی."},
  {"question": "مفهوم \"جزیره پایداری\" (Island of Stability) چیست؟", "answer": "یک پیش‌بینی تئوری مبنی بر وجود عناصری فوق سنگین با تعداد پروتون و نوترون \"جادویی\" که نیمه‌عمر طولانی‌تری دارند."},
  {"question": "چرا عدد اتمی بالا باعث ناپایداری رادیواکتیو می‌شود؟", "answer": "نیروی دافعه الکترواستاتیکی بین تعداد زیاد پروتون‌ها و همچنین نسبت نامتعادل نوترون به پروتون در هسته."},
  {"question": "چه تفاوتی بین عناصر طبیعی و مصنوعی در جدول تناوبی وجود دارد؟", "answer": "عناصر طبیعی تا عدد اتمی ۹۲ (اورانیوم) در زمین یافت می‌شوند، در حالی که عناصر با عدد اتمی بالاتر از ۹۲ عمدتاً در آزمایشگاه‌ها ساخته شده‌اند."},
  {"question": "چه کسی مفهوم \"عناصر فوق سنگین\" را مطرح کرد؟", "answer": "این مفهوم به تدریج با پیشرفت فیزیک هسته‌ای و سنتز عناصر جدید شکل گرفته است."},
  {"question": "چگونه عناصر فوق سنگین سنتز می‌شوند؟", "answer": "با برخورد دادن یون‌های اتمی سبک‌تر به یکدیگر در شتاب‌دهنده‌های ذرات."},
  {"question": "چالش اصلی در مطالعه خواص شیمیایی عناصر فوق سنگین چیست؟", "answer": "تولید تعداد کافی اتم برای انجام آزمایش‌ها و نیمه‌عمر کوتاه آن‌ها."},
  {"question": "آیا خواص شیمیایی عناصر فوق سنگین همیشه از روند کلی جدول تناوبی پیروی می‌کند؟", "answer": "خیر، در اعداد اتمی بالا، اثرات نسبیتی (Relativistic effects) می‌توانند خواص را به طور قابل توجهی تغییر دهند."},
  {"question": "عدد اتمی \"جادویی\" (Magic Numbers) در هسته‌های اتمی به چه معناست؟", "answer": "تعداد خاصی از پروتون‌ها یا نوترون‌ها که باعث پایداری بیشتر هسته می‌شود (مانند ۲، ۸، ۲۰، ۲۸، ۵۰، ۸۲، ۱۲۶)."},
  {"question": "چرا عدد اتمی ۱۱۸ (اوگانسون) را در گروه ۱۸ قرار داده‌اند؟", "answer": "بر اساس پیش‌بینی‌های تئوری که نشان می‌دهد لایه الکترونی بیرونی آن پر است و خواص گاز نجیب را خواهد داشت."},
  {"question": "تا چه عددی جدول تناوبی می‌تواند ادامه یابد؟", "answer": "به صورت تئوری تا اعداد بسیار بالاتر قابل تصور است، اما پایداری و سنتز آن‌ها بسیار دشوار خواهد بود."},
  {"question": "آیا عناصری با عدد اتمی بالاتر از ۱۱۸ کشف شده‌اند؟", "answer": "بله، عناصری مانند ۱۱۹ و ۱۲۰ در حال تلاش برای سنتز هستند، اما هنوز تایید نهایی نشده‌اند."},
  {"question": "چه عواملی باعث می‌شوند عناصر فوق سنگین رادیواکتیو باشند؟", "answer": "نسبت نامتعادل نوترون به پروتون، اندازه بزرگ هسته و انرژی زیاد آزاد شده در واپاشی."},
  {"question": "نقش \"شماره جرمی\" (Mass Number) در کنار عدد اتمی چیست؟", "answer": "شماره جرمی مجموع پروتون‌ها و نوترون‌هاست (A = Z + N) و ایزوتوپ‌های یک عنصر را از هم متمایز می‌کند."},
  {"question": "آیا عناصر دوره هفتم خواص مشابه عناصر دوره دوم دارند؟ (مثلاً Fr شبیه Li، Ra شبیه Be و...)", "answer": "در سطوح پایه بله، اما اثرات نسبیتی و اندازه بزرگتر باعث تفاوت‌هایی می‌شود."},
  {"question": "چگونه می‌توان نیمه‌عمر (Half-life) یک عنصر رادیواکتیو را اندازه‌گیری کرد؟", "answer": "با شمارش تعداد واپاشی‌ها در واحد زمان و تعیین زمانی که نیمی از اتم‌های اولیه واپاشیده‌اند."},
  {"question": "چرا مطالعه عناصر فوق سنگین مهم است؟", "answer": "برای درک بهتر قوانین فیزیک هسته‌ای، تکامل عناصر و محدودیت‌های جدول تناوبی."},
  {"question": "عنصر\"طلا\" (Gold) با نماد Au، در کدام دسته از عناصر قرار می‌گیرد؟", "answer": "فلزات واسطه (Transition Metals) در گروه ۱۱."},
  {"question": "عدد اتمی (Atomic Number) مس (Copper) با نماد Cu چند است؟", "answer": "۲۹."},
  {"question": "چه عاملی باعث می‌شود کربن (Carbon) با نماد C قادر به تشکیل چهار پیوند کووالانسی باشد؟", "answer": "چهار الکترون ظرفیت (Valence Electrons) و قابلیت تشکیل هیبرید اوربیتال‌های sp3، sp2 و sp."},
  {"question": "چرا هلیوم (Helium) با نماد He در دمای اتاق به صورت گازی وجود دارد؟", "answer": "به دلیل داشتن لایه الکترونی بیرونی کامل (۲ الکترون) که آن را بسیار پایدار و تمایل به واکنش‌ناپذیر می‌کند (گاز نجیب)."},
  {"question": "نیتروژن (Nitrogen) با نماد N، چه نقشی در جو زمین دارد؟", "answer": "حدود ۷۸٪ جو زمین را تشکیل می‌دهد و در چرخه نیتروژن و ساخت پروتئین‌ها حیاتی است."},
  {"question": "اکسیژن (Oxygen) با نماد O، مهم‌ترین نقش بیولوژیکی آن چیست؟", "answer": "تنفس سلولی (Cellular Respiration) و تولید انرژی در موجودات زنده."},
  {"question": "سدیم (Sodium) با نماد Na، چه نوع واکنشی با آب نشان می‌دهد؟", "answer": "واکنش شدید و گرمازا که منجر به تولید هیدروژن و سدیم هیدروکسید می‌شود (به دلیل خاصیت فلز قلیایی)."},
  {"question": "کلر (Chlorine) با نماد Cl، چه کاربردی در تصفیه آب دارد؟", "answer": "به عنوان یک عامل ضدعفونی کننده قوی برای از بین بردن باکتری‌ها و عوامل بیماری‌زا."},
  {"question": "گوگرد (Sulfur) با نماد S، معمولاً در چه ترکیباتی یافت می‌شود؟", "answer": "در ترکیبات معدنی (مانند سولفیدها و سولفات‌ها) و آلی (مانند اسیدهای آمینه سیستئین و متیونین)."},
  {"question": "آهن (Iron) با نماد Fe، نقش حیاتی آن در بدن انسان چیست؟", "answer": "جزء اصلی هموگلوبین در گلبول‌های قرمز که مسئول انتقال اکسیژن است."},
  {"question": "آلومینیوم (Aluminum) با نماد Al، چرا در صنعت هوافضا و بسته‌بندی کاربرد فراوان دارد؟", "answer": "سبک، مقاوم به خوردگی (به دلیل تشکیل لایه اکسید محافظ) و استحکام بالا."},
  {"question": "روی (Zinc) با نماد Zn، چه نقشی در سیستم ایمنی بدن دارد؟", "answer": "برای عملکرد صحیح سیستم ایمنی و تقسیم سلولی ضروری است."},
  {"question": "نقره (Silver) با نماد Ag، به جز زیورآلات، چه کاربرد صنعتی مهمی دارد؟", "answer": "در الکترونیک، کاتالیزورها و به دلیل خواص ضدمیکروبی در برخی پانسمان‌ها."},
  {"question": "قلع (Tin) با نماد Sn، چرا در ساخت قوطی‌های کنسرو استفاده می‌شود؟", "answer": "برای جلوگیری از خوردگی و محافظت از محتوای غذا (به عنوان پوشش روی فولاد)."},
  {"question": "ید (Iodine) با نماد I، کمبود آن در بدن چه مشکلی ایجاد می‌کند؟", "answer": "باعث اختلال در عملکرد غده تیروئید و بیماری گواتر می‌شود."},
  {"question": "باریم (Barium) با نماد Ba، چرا در تصویربرداری اشعه ایکس از دستگاه گوارش استفاده می‌شود؟", "answer": "به دلیل جذب بالای اشعه ایکس، به عنوان یک ماده حاجب (Contrast Agent) عمل می‌کند."},
  {"question": "پلاتین (Platinum) با نماد Pt، چه کاربرد مهمی در خودروها دارد؟", "answer": "به عنوان کاتالیزور در مبدل‌های کاتالیستی (Catalytic Converters) برای کاهش آلایندگی."},
  {"question": "طلا (Au) با نماد Au، چه خواصی باعث شده تا در دندانپزشکی و الکترونیک استفاده شود؟", "answer": "مقاومت بالا به خوردگی، رسانایی الکتریکی عالی و انعطاف‌پذیری."},
  {"question": "جیوه (Mercury) با نماد Hg، چرا استفاده از آن در دماسنج‌ها و ترموستات‌ها محدود شده است؟", "answer": "سمی بودن بخارات آن و خطرات زیست‌محیطی."},
  {"question": "اورانیوم (Uranium) با نماد U، کاربرد اصلی آن چیست؟", "answer": "سوخت در راکتورهای هسته‌ای برای تولید انرژی الکتریکی."},
  {"question": "هیدروژن (Hydrogen) با نماد H، سبک‌ترین و فراوان‌ترین عنصر در جهان چیست؟", "answer": "بله، سبک‌ترین و فراوان‌ترین عنصر است."},
  {"question": "هالوژن‌ها (Halogens) مانند فلور (F)، کلر (Cl)، برم (Br) و ید (I)، چه ویژگی مشترکی دارند؟", "answer": "هفت الکترون ظرفیت، بسیار واکنش‌پذیر و تمایل به گرفتن یک الکترون برای تشکیل یون منفی (هالید)."},
  {"question": "گازهای نجیب (Noble Gases) مانند نئون (Ne)، آرگون (Ar)، زنون (Xe) و ...، چرا واکنش‌پذیری بسیار کمی دارند؟", "answer": "به دلیل داشتن لایه الکترونی بیرونی کامل (هشت الکترون ظرفیت، به جز هلیوم)."},
  {"question": "فلزات قلیایی (Alkali Metals) مانند لیتیوم (Li)، سدیم (Na)، پتاسیم (K) و ...، چه ویژگی برجسته‌ای دارند؟", "answer": "بسیار نرم، واکنش‌پذیر (به ویژه با آب) و تمایل به از دست دادن یک الکترون برای تشکیل یون مثبت +1."},
  {"question": "فلزات قلیایی خاکی (Alkaline Earth Metals) مانند بریلیوم (Be)، منیزیم (Mg)، کلسیم (Ca) و ...، چه تفاوتی با فلزات قلیایی دارند؟", "answer": "کمی سخت‌تر، واکنش‌پذیری کمتر و تمایل به از دست دادن دو الکترون برای تشکیل یون مثبت +2."},
  {"question": "عناصر واسطه (Transition Elements) مانند آهن (Fe)، مس (Cu)، نیکل (Ni) و ...، چه ویژگی‌هایی دارند؟", "answer": "معمولاً جامد، نقطه ذوب و جوش بالا، رسانای خوب گرما و الکتریسیته، و تشکیل یون‌های با اعداد اکسایش مختلف."},
  {"question": "لانتانیدها (Lanthanides) و اکتینیدها (Actinides) که در پایین جدول قرار دارند، چه ویژگی مشترکی دارند؟", "answer": "پر شدن اوربیتال‌های f، خواص شیمیایی مشابه یکدیگر و در مورد اکتینیدها، رادیواکتیو بودن."},
  {"question": "کدام عنصر بیشترین تعداد ایزوتوپ پایدار را دارد؟", "answer": "قلع (Tin) با ۱۰ ایزوتوپ پایدار."},
  {"question": "چرا برخی عناصر مانند فسفر (Phosphorus) با نماد P در اشکال مختلف (آلوتروپ) مانند فسفر سفید و قرمز وجود دارند؟", "answer": "به دلیل تفاوت در نحوه پیوند اتم‌ها با یکدیگر در حالت جامد."},
  {"question": "نقش کلسیم (Calcium) با نماد Ca در بدن چیست؟", "answer": "تشکیل و استحکام استخوان‌ها و دندان‌ها، و همچنین در انقباض عضلانی و انتقال پیام‌های عصبی."},
  {"question": "منیزیم (Magnesium) با نماد Mg، چه نقشی در فتوسنتز دارد؟", "answer": "جزء مرکزی مولکول کلروفیل که مسئول جذب نور خورشید است."},
  {"question": "سیلیکون (Silicon) با نماد Si، چرا ماده اصلی در صنعت نیمه‌هادی‌ها (Semiconductors) است؟", "answer": "خواص الکتریکی آن بین رسانا و نارسانا قرار دارد و می‌توان آن را کنترل کرد."},
  {"question": "آرسنیک (Arsenic) با نماد As، چه خاصیتی دارد که آن را در گذشته به عنوان سم استفاده می‌کردند؟", "answer": "سمی بودن بالا برای سیستم عصبی و اندام‌های حیاتی."},
  {"question": "تلوریم (Tellurium) با نماد Te، چه ویژگی جالبی دارد؟", "answer": "با برخی فلزات آلیاژهایی تشکیل می‌دهد که خواص جالبی دارند و به عنوان نیمه‌رسانا نیز کاربرد دارد."},
  {"question": "تنگستن (Tungsten) با نماد W، بالاترین نقطه ذوب را در بین فلزات دارد. این چه کاربردی برای آن ایجاد می‌کند؟", "answer": "در ساخت رشته لامپ‌های رشته‌ای، ابزارهای برش با سرعت بالا و الکترودهای جوشکاری."},
  {"question": "پتاسیم (Potassium) با نماد K، چه نقشی در تعادل مایعات بدن و عملکرد اعصاب دارد؟", "answer": "به عنوان یک الکترولیت مهم، در حفظ پتانسیل غشای سلولی و انتقال پیام‌های عصبی نقش دارد."},
  {"question": "کبالت (Cobalt) با نماد Co، چه نقشی در ویتامین B12 دارد؟", "answer": "جزء مرکزی ویتامین B12 است که برای تشکیل گلبول‌های قرمز و عملکرد سیستم عصبی ضروری است."},
  {"question": "روی (Zinc) با نماد Zn، به جز سیستم ایمنی، چه نقش دیگری در بدن دارد؟", "answer": "ضروری برای ترمیم زخم، حس چشایی و بویایی، و سنتز DNA."},
  {"question": "نئون (Neon) با نماد Ne، چرا در تابلوهای تبلیغاتی نورانی استفاده می‌شود؟", "answer": "هنگامی که الکتریسیته از آن عبور می‌کند، نور قرمز-نارنجی درخشانی تولید می‌کند."},
  {"question": "آرگون (Argon) با نماد Ar، چرا در صنعت جوشکاری (مانند جوشکاری TIG) به عنوان گاز محافظ استفاده می‌شود؟", "answer": "به دلیل واکنش‌ناپذیری، از اکسید شدن فلز در دمای بالا جلوگیری می‌کند."},
  {"question": "کروم (Chromium) با نماد Cr، چه خواصی به فولاد ضد زنگ (Stainless Steel) می‌بخشد؟", "answer": "مقاومت به خوردگی و درخشندگی زیبا."},
  {"question": "وانادیم (Vanadium) با نماد V، چه کاربردی در ساخت آلیاژهای فولادی دارد؟", "answer": "افزودن وانادیم به فولاد، استحکام و مقاومت آن را در برابر ضربه افزایش می‌دهد."},
  {"question": "مولیبدن (Molybdenum) با نماد Mo، چه خواصی را به فولادهای ابزار می‌دهد؟", "answer": "افزایش سختی، مقاومت به سایش و حفظ سختی در دماهای بالا."},
  {"question": "پالادیوم (Palladium) با نماد Pd، چه کاربردی در صنعت جواهرسازی و کاتالیزورها دارد؟", "answer": "در آلیاژهای طلا (طلای سفید)، و به عنوان کاتالیزور در واکنش‌های شیمیایی و مبدل‌های کاتالیستی."},
  {"question": "پلوتونیوم (Plutonium) با نماد Pu، علاوه بر کاربردهای نظامی، چه استفاده دیگری دارد؟", "answer": "در ژنراتورهای ترموالکتریک رادیوایزوتوپی (RTGs) برای تأمین انرژی فضاپیماها."},
  {"question": "رادون (Radon) با نماد Rn، چرا یک گاز نجیب خطرناک محسوب می‌شود؟", "answer": "رادیواکتیو بودن آن و سرطان‌زا بودن در صورت تجمع در فضاهای بسته."},
  {"question": "فرانسیم (Francium) با نماد Fr، چرا بسیار نادر و رادیواکتیو است؟", "answer": "آخرین عنصر دوره هفتم و به سرعت واپاشیده می‌شود، نیمه‌عمر بسیار کوتاهی دارد."},
  {"question": "کدام وسیله آزمایشگاهی برای اندازه‌گیری دقیق حجم مایعات استفاده می‌شود؟", "answer": "بورت (Burette) یا پیپت حجمی (Volumetric Pipette)."},
  {"question": "عملکرد اصلی میکروسکوپ نوری (Light Microscope) چیست؟", "answer": "بزرگنمایی نمونه‌های کوچک که با چشم غیرمسلح دیده نمی‌شوند."},
  {"question": "چرا در آزمایشگاه از هود شیمیایی (Fume Hood) استفاده می‌کنیم؟", "answer": "برای تخلیه بخارات و گازهای سمی و مضر از محیط آزمایشگاه."},
  {"question": "دستگاه سانتریفیوژ (Centrifuge) چه کاری انجام می‌دهد؟", "answer": "با چرخش سریع نمونه‌ها، اجزای سنگین‌تر را از اجزای سبک‌تر جدا می‌کند."},
  {"question": "pH متر (pH Meter) چه پارامتری را اندازه‌گیری می‌کند؟", "answer": "میزان اسیدی یا بازی بودن یک محلول (مقدار pH)."},
  {"question": "دستگاه اسپکتروفتومتر (Spectrophotometer) چگونه کار می‌کند؟", "answer": "میزان جذب یا عبور نور از یک نمونه را در طول موج‌های مختلف اندازه‌گیری می‌کند."},
  {"question": "فرق اصلی بین ارلن (Erlenmeyer Flask) و بشر (Beaker) چیست؟", "answer": "ارلن برای مخلوط کردن، گرم کردن و تیتراسیون طراحی شده و دهانه باریک‌تری دارد، در حالی که بشر برای مخلوط کردن و حرارت دادن عمومی کاربرد دارد."},
  {"question": "کدام ابزار برای انتقال مقادیر مشخص و دقیق مایعات استفاده می‌شود؟", "answer": "پیپت (Pipette)، شامل پیپت حجمی و پیپت مدرج."},
  {"question": "کاربرد اصلی اتوکلاو (Autoclave) در آزمایشگاه چیست؟", "answer": "استریل کردن ابزار و مواد با استفاده از بخار تحت فشار بالا."},
  {"question": "دستگاه کروماتوگرافی گازی (Gas Chromatography - GC) برای جداسازی کدام نوع ترکیبات مناسب است؟", "answer": "ترکیبات فرار (Volatile Compounds)."},
  {"question": "دستگاه کروماتوگرافی مایع با کارایی بالا (High-Performance Liquid Chromatography - HPLC) چه کاربردی دارد؟", "answer": "جداسازی، شناسایی و تعیین مقدار ترکیبات غیرفرار در مایعات."},
  {"question": "دستگاه طیف‌سنجی جرمی (Mass Spectrometry - MS) چه اطلاعاتی در مورد یک نمونه به ما می‌دهد؟", "answer": "جرم مولکولی ترکیبات و اطلاعات ساختاری آن‌ها بر اساس نسبت جرم به بار."},
  {"question": "دستگاه PCR (Polymerase Chain Reaction) برای چه منظوری استفاده می‌شود؟", "answer": "تکثیر (تکثیر) قطعات خاصی از DNA."},
  {"question": "کاربرد الایزا (ELISA - Enzyme-Linked Immunosorbent Assay) در آزمایشگاه چیست؟", "answer": "تشخیص و اندازه‌گیری حضور آنتی‌ژن‌ها یا آنتی‌بادی‌ها در نمونه‌ها."},
  {"question": "آزمایش تیتراسیون (Titration) برای تعیین چیست؟", "answer": "غلظت دقیق یک محلول ناشناخته با استفاده از محلول استاندارد."},
  {"question": "آزمایش تست سوز (Streak Plate Test) برای جداسازی کدام موجودات زنده استفاده می‌شود؟", "answer": "جداسازی کلنی‌های باکتری از یک نمونه پیچیده روی محیط کشت جامد."},
  {"question": "آزمایش گرم (Gram Staining) برای طبقه‌بندی کدام نوع سلول‌ها به کار می‌رود؟", "answer": "طبقه‌بندی باکتری‌ها بر اساس ساختار دیواره سلولی به گرم مثبت و گرم منفی."},
  {"question": "دستگاه الکتروفورز (Electrophoresis) چگونه مولکول‌های DNA را جدا می‌کند؟", "answer": "با استفاده از میدان الکتریکی، مولکول‌های DNA را بر اساس اندازه و بارشان روی ژل حرکت می‌دهد."},
  {"question": "کاربرد اصلی کوره الکتریکی (Electric Furnace) در آزمایشگاه چیست؟", "answer": "حرارت دادن نمونه‌ها تا دماهای بسیار بالا، مثلاً برای خاکسترگیری یا ذوب مواد."},
  {"question": "دستگاه استخراج کننده سوکسله (Soxhlet Extractor) برای استخراج چه موادی به کار می‌رود؟", "answer": "ترکیبات آلی محلول در حلال از مواد جامد (مانند استخراج روغن از دانه‌ها)."},
  {"question": "آزمایش تعیین نقطه ذوب (Melting Point Determination) چه اطلاعاتی در مورد یک ماده جامد می‌دهد؟", "answer": "خلوص ماده؛ نقطه ذوب پایین و گسترده معمولاً نشان‌دهنده ناخالصی است."},
  {"question": "دستگاه رفلاکتومتر (Refractometer) چه پارامتری را اندازه‌گیری می‌کند؟", "answer": "ضریب شکست نور یک مایع، که با غلظت آن رابطه دارد."},
  {"question": "کاربرد دستگاه طیف‌سنجی مادون قرمز (Infrared Spectroscopy - IR) چیست؟", "answer": "شناسایی گروه‌های عاملی موجود در یک مولکول آلی."},
  {"question": "دستگاه رزونانس مغناطیسی هسته‌ای (Nuclear Magnetic Resonance - NMR) چه اطلاعات دقیقی از ساختار مولکولی ارائه می‌دهد؟", "answer": "اطلاعات جامعی در مورد اتم‌ها، پیوندها و هندسه مولکول."},
  {"question": "آزمایش فتوسنتز، چگونه میزان جذب CO2 یا تولید O2 توسط گیاهان اندازه‌گیری می‌شود؟", "answer": "با استفاده از دستگاه‌هایی مانند فتوسنتز متر یا با اندازه‌گیری تغییرات غلظت گازها در یک سیستم بسته."},
  {"question": "دستگاه مولتی‌متر (Multimeter) چه کمیت‌های الکتریکی را می‌تواند اندازه‌گیری کند؟", "answer": "ولتاژ (Voltage)، جریان (Current) و مقاومت (Resistance)."},
  {"question": "کاربرد اصلی انکوباتور (Incubator) در آزمایشگاه چیست؟", "answer": "فراهم کردن شرایط دمایی ثابت و کنترل شده برای رشد میکروارگانیسم‌ها یا سلول‌ها."},
  {"question": "دستگاه آب مقطر ساز (Distillation Apparatus) برای تولید کدام نوع آب استفاده می‌شود؟", "answer": "آب مقطر (Distilled Water) که ناخالصی‌های معدنی آن حذف شده است."},
  {"question": "آزمایش تعیین ویسکوزیته (Viscosity Measurement)، چه خاصیتی از مایع را نشان می‌دهد؟", "answer": "مقاومت مایع در برابر جریان یافتن (میزان روان بودن یا غلظت)."},
  {"question": "دستگاه ژل الکتروفورز (Gel Electrophoresis) برای جداسازی کدام نوع مولکول‌های زیستی به کار می‌رود؟", "answer": "DNA، RNA و پروتئین‌ها."},
  {"question": "دستگاه کلنی کانتر (Colony Counter) برای چه کاری طراحی شده است؟", "answer": "شمارش خودکار یا نیمه‌خودکار کلنی‌های باکتری یا قارچ روی پلیت‌های کشت."},
  {"question": "آزمایش تست حساسیت آنتی‌بیوتیکی (Antibiotic Susceptibility Testing)، چه اطلاعاتی در مورد باکتری‌ها به ما می‌دهد؟", "answer": "اینکه کدام آنتی‌بیوتیک‌ها بر روی یک سویه خاص باکتری مؤثر هستند."},
  {"question": "دستگاه سانتریفیوژ یخچال‌دار (Refrigerated Centrifuge) چه مزیتی نسبت به سانتریفیوژ معمولی دارد؟", "answer": "حفظ دمای پایین نمونه‌ها در حین چرخش، که برای نمونه‌های حساس به دما ضروری است."},
  {"question": "کاربرد دستگاه PCR آنی (Real-time PCR) چیست؟", "answer": "تکثیر DNA همراه با اندازه‌گیری کمی محصول در هر سیکل، برای تعیین مقدار اولیه DNA."},
  {"question": "دستگاه فلوسایتومتر (Flow Cytometer) چه نوع تحلیل‌هایی را روی سلول‌ها انجام می‌دهد؟", "answer": "شمارش سلول‌ها، شناسایی انواع سلول‌ها و اندازه‌گیری خواص فیزیکی و شیمیایی آن‌ها در حالت معلق."},
  {"question": "آزمایش کشت سلول (Cell Culture)، چه هدفی را دنبال می‌کند؟", "answer": "نگهداری و رشد سلول‌های زنده در خارج از بدن (in vitro) برای تحقیقات."},
  {"question": "دستگاه استریومیکروسکوپ (Stereomicroscope) یا لوپ، چه تفاوتی با میکروسکوپ نوری دارد؟", "answer": "بزرگنمایی کمتر اما دید سه بعدی و عمق بیشتری ارائه می‌دهد، مناسب برای مشاهده اجسام درشت‌تر."},
  {"question": "کاربرد اصلی دستگاه کروماتوگرافی لایه نازک (Thin-Layer Chromatography - TLC) چیست؟", "answer": "جداسازی سریع، شناسایی و تعیین خلوص ترکیبات در مقیاس کوچک."},
  {"question": "دستگاه پتانسیومتر (Potentiometer) چه زمانی استفاده می‌شود؟", "answer": "برای اندازه‌گیری دقیق اختلاف پتانسیل الکتریکی یا تعیین نقطه پایانی در برخی تیتراسیون‌ها."},
  {"question": "آزمایش تعیین نقطه جوش (Boiling Point Determination) چه اطلاعاتی در مورد یک مایع می‌دهد؟", "answer": "معمولاً برای تأیید هویت یک حلال یا حین استخراج/تقطیر استفاده می‌شود."},
  {"question": "دستگاه کندانسور (Condenser) در تقطیر چه نقشی دارد؟", "answer": "خنک کردن بخارات و تبدیل آن‌ها به مایع (میعان)."},
  {"question": "کاربرد اصلی دستگاه هموژنایزر (Homogenizer) چیست؟", "answer": "یکسان‌سازی بافت‌ها یا مخلوط کردن مواد جامد و مایع برای ایجاد یکنواختی."},
  {"question": "آزمایش سنجش فعالیت آنزیم (Enzyme Activity Assay)، چه چیزی را اندازه‌گیری می‌کند؟", "answer": "سرعت واکنش کاتالیز شده توسط یک آنزیم خاص."},
  {"question": "دستگاه اسپکترومتر جرمی با یونیزاسیون الکترواسپری (ESI-MS) چه نوع نمونه‌هایی را می‌تواند تحلیل کند؟", "answer": "مولکول‌های زیستی بزرگ و غیرفرار مانند پروتئین‌ها و پپتیدها."},
  {"question": "آزمایش استخراج DNA، چه مراحلی را معمولاً شامل می‌شود؟", "answer": "لیز کردن سلول‌ها، حذف پروتئین‌ها و RNA، و خالص‌سازی DNA."},
  {"question": "دستگاه سیکوئنسر DNA (DNA Sequencer) چه اطلاعاتی در مورد DNA ارائه می‌دهد؟", "answer": "ترتیب نوکلئوتیدها (A, T, C, G) در یک رشته DNA."},
  {"question": "آزمایش رنگ‌آمیزی سودان (Sudan Staining) برای شناسایی کدام دسته از ترکیبات آلی استفاده می‌شود؟", "answer": "چربی‌ها و لیپیدها."},
  {"question": "دستگاه استخراج کننده مایع-مایع (Liquid-Liquid Extractor) چگونه کار می‌کند؟", "answer": "با استفاده از حلال‌های غیرقابل امتزاج، ترکیبات مورد نظر را از یک فاز مایع به فاز دیگر منتقل می‌کند."},
  {"question": "واحد اصلی ساختار و عملکرد در تمام موجودات زنده چیست؟", "answer": "سلول (Cell)."},
  {"question": "فرآیند تبدیل نور خورشید به انرژی شیمیایی توسط گیاهان چه نام دارد؟", "answer": "فتوسنتز (Photosynthesis)."},
  {"question": "عنصر شیمیایی با نماد O و عدد اتمی ۸ چیست؟", "answer": "اکسیژن (Oxygen)."},
  {"question": "قانون دوم نیوتن بیان می‌کند که شتاب یک جسم با چه عواملی نسبت عکس و نسبت مستقیم دارد؟", "answer": "نسبت عکس با جرم و نسبت مستقیم با نیروی وارد بر آن."},
  {"question": "ماده‌ای که در حالت جامد، مایع و گاز وجود دارد و نقش حیاتی در حیات دارد چیست؟", "answer": "آب (H2O)."},
  {"question": "واکنش شیمیایی که گرما جذب می‌کند چه نام دارد؟", "answer": "واکنش گرماگیر (Endothermic Reaction)."},
  {"question": "کدام اندامک در سلول‌های یوکاریوتی مسئول تولید انرژی (ATP) است؟", "answer": "میتوکندری (Mitochondrion)."},
  {"question": "واحد اندازه‌گیری نیرو در سیستم SI چیست؟", "answer": "نیوتن (Newton)."},
  {"question": "ترکیب شیمیایی DNA مخفف چیست و چه نقشی دارد؟", "answer": "Deoxyribonucleic Acid؛ حامل اطلاعات ژنتیکی."},
  {"question": "پدیده‌ای که در آن نور هنگام عبور از محیطی به محیط دیگر تغییر مسیر می‌دهد چه نام دارد؟", "answer": "شکست نور (Refraction)."},
  {"question": "چه فرآیندی باعث می‌شود که مواد در حالت جامد مستقیماً به گاز تبدیل شوند؟", "answer": "تصعید (Sublimation)."},
  {"question": "واحد اندازه‌گیری مقاومت الکتریکی چیست؟", "answer": "اهم (Ohm)."},
  {"question": "کدام گروه از ماکرومولکول‌های زیستی مسئول ساختار و ترمیم بافت‌ها هستند؟", "answer": "پروتئین‌ها (Proteins)."},
  {"question": "قانون بقای انرژی بیان می‌کند که انرژی چگونه است؟", "answer": "انرژی نه خلق می‌شود و نه از بین می‌رود، بلکه از شکلی به شکل دیگر تبدیل می‌شود."},
  {"question": "چه واکنشی در ستاره‌ها منبع اصلی انرژی آن‌هاست؟", "answer": "واکنش همجوشی هسته‌ای (Nuclear Fusion)."},
  {"question": "کدام نوع سلول در خون مسئول حمل اکسیژن است؟", "answer": "گلبول قرمز (Red Blood Cell)."},
  {"question": "واحد اندازه‌گیری انرژی چیست؟", "answer": "ژول (Joule)."},
  {"question": "مولکول آلی که واحد سازنده کربوهیدرات‌هاست چه نام دارد؟", "answer": "مونوساکارید (Monosaccharide)، مانند گلوکز."},
  {"question": "تأثیر میدان مغناطیسی بر سیم حامل جریان الکتریکی چیست؟", "answer": "نیرویی بر سیم وارد می‌شود (اساس کار موتورهای الکتریکی)."},
  {"question": "چه پدیده‌ای باعث می‌شود رنگین‌کمان در آسمان ظاهر شود؟", "answer": "شکست و بازتاب نور خورشید توسط قطرات باران."},
  {"question": "کدام گاز در جو زمین برای تنفس اکثر موجودات زنده ضروری است؟", "answer": "اکسیژن (Oxygen)."},
  {"question": "فرآیند شکست مولکول‌های بزرگ به مولکول‌های کوچکتر با کمک آب چه نام دارد؟", "answer": "هیدرولیز (Hydrolysis)."},
  {"question": "واحد اندازه‌گیری توان الکتریکی چیست؟", "answer": "وات (Watt)."},
  {"question": "کدام بخش از سلول گیاهی مسئول فتوسنتز است؟", "answer": "کلروپلاست (Chloroplast)."},
  {"question": "پدیده‌ی تبخیر آب از سطح برگ گیاهان چه نام دارد؟", "answer": "تعرق (Transpiration)."},
  {"question": "واحد اندازه‌گیری فشار چیست؟", "answer": "پاسکال (Pascal)."},
  {"question": "چه نوع انرژی در سوخت‌های فسیلی ذخیره شده است؟", "answer": "انرژی شیمیایی (Chemical Energy)."},
  {"question": "مفهوم 'نقطه انجماد' (Freezing Point) به چه معناست؟", "answer": "دمایی که در آن یک مایع به جامد تبدیل می‌شود."},
  {"question": "کدام گروه از عناصر در جدول تناوبی به دلیل واکنش‌پذیری کم، گازهای نجیب نامیده می‌شوند؟", "answer": "گروه ۱۸ (Noble Gases)."},
  {"question": "فرآیند تبدیل بخار آب به مایع چه نام دارد؟", "answer": "میعان (Condensation)."},
  {"question": "واحد اندازه‌گیری جریان الکتریکی چیست؟", "answer": "آمپر (Ampere)."},
  {"question": "کدام اسید آمینه واحد سازنده پروتئین‌هاست؟", "answer": "اسیدهای آمینه (Amino Acids)."},
  {"question": "اصطکاک (Friction) چه نوع نیرویی است و معمولاً چه اثری دارد؟", "answer": "نیرویی مقاومتی که بین سطوح در تماس عمل می‌کند و باعث کاهش سرعت یا اتلاف انرژی می‌شود."},
  {"question": "کدام بخش از چشم مسئول تمرکز نور بر روی شبکیه است؟", "answer": "عدسی (Lens)."},
  {"question": "فرآیند تقسیم سلولی که منجر به تولید دو سلول دختری یکسان می‌شود چه نام دارد؟", "answer": "میتوز (Mitosis)."},
  {"question": "واحد اندازه‌گیری بار الکتریکی چیست؟", "answer": "کولن (Coulomb)."},
  {"question": "کدام گروه از مواد در بدن نقش ذخیره انرژی بلند مدت را دارند؟", "answer": "چربی‌ها (Lipids)."},
  {"question": "اگر جسمی در آب شناور باشد، چگالی آن نسبت به چگالی آب چگونه است؟", "answer": "کمتر است."},
  {"question": "کدام گاز گلخانه‌ای اصلی‌ترین عامل گرمایش جهانی است؟", "answer": "دی‌اکسید کربن (CO2)."},
  {"question": "فرآیند تولید انرژی در سلول‌های زنده بدون نیاز به اکسیژن چه نام دارد؟", "answer": "تخمیر (Fermentation)."},
  {"question": "واحد اندازه‌گیری فرکانس امواج چیست؟", "answer": "هرتز (Hertz)."},
  {"question": "کدام ویتامین برای جذب کلسیم ضروری است؟", "answer": "ویتامین D."},
  {"question": "تفاوت اصلی بین امواج طولی (Longitudinal) و عرضی (Transverse) چیست؟", "answer": "در امواج طولی، ذرات در راستای انتشار موج نوسان می‌کنند (مانند امواج صوتی)؛ در امواج عرضی، ذرات عمود بر راستای انتشار موج نوسان می‌کنند (مانند امواج نور)."},
  {"question": "کدام نوع سلول در گیاهان مسئول انتقال آب و مواد معدنی است؟", "answer": "آوند چوبی (Xylem)."},
  {"question": "واکنش شیمیایی که گرما آزاد می‌کند چه نام دارد؟", "answer": "واکنش گرماده (Exothermic Reaction)."},
  {"question": "واحد اندازه‌گیری دما در مقیاس مطلق چیست؟", "answer": "کلوین (Kelvin)."},
  {"question": "مفهوم 'تابش' (Radiation) در فیزیک به چه نوع انتقال انرژی اشاره دارد؟", "answer": "انتقال انرژی از طریق امواج الکترومغناطیسی یا ذرات پرانرژی."},
  {"question": "کدام گروه از عناصر شیمیایی، رسانایی الکتریکی و حرارتی خوبی دارند و معمولاً در سمت چپ جدول تناوبی قرار دارند؟", "answer": "فلزات (Metals)."},
  {"question": "فرآیند تولید مثل جنسی در گیاهان شامل چه مراحلی است؟", "answer": "گرده‌افشانی، لقاح و تشکیل دانه و میوه."},
  {"question": "واحد اندازه‌گیری توان (قدرت) در سیستم SI چیست؟", "answer": "وات (Watt)."},
  {"question": "دقیق‌ترین روش برای اندازه‌گیری حجم مایعات در آزمایشگاه چیست؟", "answer": "بورت (Burette) برای تیتراسیون و پیپت حجمی (Volumetric Pipette) برای برداشتن حجم دقیق."},
  {"question": "کاربرد اصلی میکروسکوپ الکترونی عبوری (TEM) چیست؟", "answer": "مشاهده ساختارهای داخلی سلول‌ها و مواد در مقیاس نانو با وضوح بسیار بالا."},
  {"question": "روش استریل کردن اتوکلاو (Autoclave) بر چه اصلی استوار است؟", "answer": "استفاده از بخار آب داغ تحت فشار بالا برای از بین بردن میکروارگانیسم‌ها."},
  {"question": "کدام تکنیک جداسازی برای جدا کردن ترکیبات بر اساس اختلاف نقطه جوش آن‌ها استفاده می‌شود؟", "answer": "تقطیر (Distillation)."},
  {"question": "چرا هنگام کار با مواد شیمیایی خورنده باید از عینک ایمنی استفاده کرد؟", "answer": "برای محافظت از چشم‌ها در برابر پاشش مواد و جلوگیری از آسیب جدی."},
  {"question": "نام دستگاهی که برای اندازه‌گیری pH محلول‌ها استفاده می‌شود چیست؟", "answer": "pH متر (pH Meter)."},
  {"question": "کاربرد سانتریفیوژ (Centrifuge) در آزمایشگاه چیست؟", "answer": "جداسازی اجزای مایع یا جامد با استفاده از نیروی گریز از مرکز بر اساس چگالی."},
  {"question": "کدام روش کروماتوگرافی برای جداسازی مولکول‌های زیستی مانند پروتئین‌ها و اسیدهای نوکلئیک بر اساس اندازه و بار الکتریکی استفاده می‌شود؟", "answer": "الکتروفورز (Electrophoresis)."},
  {"question": "چرا در آزمایشگاه‌های میکروبیولوژی، سرنگ‌ها و ظروف کشت باید استریل باشند؟", "answer": "برای جلوگیری از آلودگی نمونه با میکروارگانیسم‌های ناخواسته و اطمینان از نتایج دقیق آزمایش."},
  {"question": "نام ظروف شیشه‌ای که معمولاً برای حرارت دادن مایعات در آزمایشگاه استفاده می‌شوند چیست؟", "answer": "ارلن مایر (Erlenmeyer Flask) یا بشر (Beaker)."},
  {"question": "کدام تکنیک جداسازی بر اساس اختلاف حلالیت ترکیبات در دو فاز (معمولاً جامد و مایع) عمل می‌کند؟", "answer": "استخراج (Extraction)."},
  {"question": "کاربرد اصلی اسپکتروفتومتر (Spectrophotometer) چیست؟", "answer": "اندازه‌گیری میزان جذب یا عبور نور توسط یک نمونه در طول موج‌های مختلف برای تعیین غلظت یا شناسایی ماده."},
  {"question": "چرا هنگام کار با مواد فرار یا سمی در آزمایشگاه، از هود شیمیایی (Fume Hood) استفاده می‌کنیم؟", "answer": "برای تخلیه بخارات و گازهای مضر به بیرون از فضای آزمایشگاه و محافظت از کارکنان."},
  {"question": "نام روشی که در آن از یک محلول با غلظت مشخص برای تعیین غلظت محلول دیگر استفاده می‌شود چیست؟", "answer": "تیتراسیون (Titration)."},
  {"question": "کدام نوع میکروسکوپ برای مشاهده نمونه‌های زنده بدون نیاز به رنگ‌آمیزی یا تثبیت استفاده می‌شود؟", "answer": "میکروسکوپ کنتراست فاز (Phase Contrast Microscope)."},
  {"question": "چرا باید از دستکش‌های یکبار مصرف هنگام کار با مواد شیمیایی یا نمونه‌های بیولوژیکی استفاده کرد؟", "answer": "برای جلوگیری از تماس مستقیم پوست با مواد و محافظت از خود و جلوگیری از آلودگی نمونه."},
  {"question": "نام دستگاهی که برای اندازه‌گیری دقیق جرم مواد در آزمایشگاه استفاده می‌شود چیست؟", "answer": "ترازوی آزمایشگاهی (Laboratory Balance) یا ترازوی دقیق (Analytical Balance)."},
  {"question": "کدام تکنیک جداسازی برای جدا کردن اجزای مخلوط بر اساس اختلاف نقطه ذوب یا تبخیر آن‌ها به کار می‌رود؟", "answer": "تبلور مجدد (Recrystallization) یا تقطیر (Distillation)."},
  {"question": "کاربرد اصلیPCR (Polymerase Chain Reaction) در زیست‌شناسی مولکولی چیست؟", "answer": "تکثیر (آمپلی‌فیکاسیون) قطعات خاصی از DNA."},
  {"question": "چرا باید درب محلول‌های شیمیایی پس از استفاده بسته شود؟", "answer": "برای جلوگیری از تبخیر شدن، آلودگی و واکنش با هوا یا رطوبت."},
  {"question": "نام ظروف کوچک و تخت شیشه‌ای که برای کشت سلول‌ها یا میکروارگانیسم‌ها استفاده می‌شوند چیست؟", "answer": "پتری دیش (Petri Dish)."},
  {"question": "کدام تکنیک جداسازی برای جداسازی ترکیبات بر اساس اختلاف فشار بخار آن‌ها در دماهای مختلف استفاده می‌شود؟", "answer": "تقطیر (Distillation)."},
  {"question": "کاربرد اصلی دستگاه رفلاکتومتر (Refractometer) چیست؟", "answer": "اندازه‌گیری ضریب شکست نور در مایعات برای تعیین غلظت یا خلوص آن‌ها."},
  {"question": "چرا در برخی آزمایش‌های شیمیایی، نیاز به انجام واکنش در محیط خلاء (Vacuum) است؟", "answer": "برای کاهش نقطه جوش حلال‌ها، جلوگیری از واکنش با اکسیژن هوا یا حذف ناخالصی‌های فرار."},
  {"question": "نام بخش مرکزی مولکول DNA که اطلاعات ژنتیکی را در بر دارد چیست؟", "answer": "هسته سلول (Nucleus) که حاوی DNA است."},
  {"question": "کدام تکنیک جداسازی برای جدا کردن ترکیبات بر اساس اختلاف اندازه مولکولی آن‌ها در یک ستون پر شده از ژل استفاده می‌شود؟", "answer": "کروماتوگرافی ژل تراوشی (Size Exclusion Chromatography / Gel Filtration)."},
  {"question": "کاربرد اصلی دستگاه طیف‌سنجی جرمی (Mass Spectrometry) چیست؟", "answer": "تعیین جرم مولکولی ترکیبات و تجزیه و تحلیل ساختار آن‌ها با اندازه‌گیری نسبت جرم به بار یون‌ها."},
  {"question": "چرا باید از ظروف تمیز و خشک هنگام اندازه‌گیری حجم مایعات استفاده کرد؟", "answer": "برای جلوگیری از خطای حجمی ناشی از حضور مایع قبلی یا آلودگی."},
  {"question": "نام روشی برای جداسازی جامدات از مایعات با استفاده از اختلاف فشار که در دو طرف یک غشای نیمه‌تراوا عمل می‌کند چیست؟", "answer": "فیلتراسیون (Filtration) یا اولترافیلتراسیون (Ultrafiltration)."},
  {"question": "کدام تکنیک جداسازی برای شناسایی و کمی‌سازی ترکیبات موجود در یک مخلوط پیچیده با استفاده از فاز متحرک و فاز ثابت به کار می‌رود؟", "answer": "کروماتوگرافی (Chromatography) به طور کلی (مانند HPLC, GC)."},
  {"question": "کاربرد اصلی دستگاه pH متر چیست؟", "answer": "اندازه‌گیری اسیدیته یا بازی بودن یک محلول آبی."},
  {"question": "چرا باید مواد شیمیایی را بر اساس سازگاری آن‌ها با هم در یک محل نگهداری کرد؟", "answer": "برای جلوگیری از واکنش‌های خطرناک، اشتعال یا تولید گازهای سمی."},
  {"question": "نام روشی برای اندازه‌گیری ویسکوزیته (Viscosity) یا گرانروی مایعات چیست؟", "answer": "ویسکومتر (Viscometer)."},
  {"question": "کدام تکنیک جداسازی برای جداسازی اجزای مخلوط بر اساس اختلاف نقطه جوش و فشار بخار آن‌ها در فاز گازی استفاده می‌شود؟", "answer": "کروماتوگرافی گازی (Gas Chromatography - GC)."},
  {"question": "کاربرد اصلی دستگاه اسپکتروسکوپی رزونانس مغناطیسی هسته (NMR) چیست؟", "answer": "تعیین دقیق ساختار مولکولی ترکیبات آلی با بررسی خواص مغناطیسی هسته‌های اتمی."},
  {"question": "چرا باید هنگام کار با دستگاه‌های الکتریکی در آزمایشگاه، از اتصال زمین مناسب اطمینان حاصل کرد؟", "answer": "برای جلوگیری از برق‌گرفتگی و محافظت از دستگاه‌ها در برابر نوسانات ولتاژ."},
  {"question": "نام وسیله‌ای که برای گرم کردن یکنواخت و کنترل شده مایعات در دمای بالا استفاده می‌شود چیست؟", "answer": "حمام آب (Water Bath) یا حمام روغن (Oil Bath)."},
  {"question": "کدام تکنیک جداسازی برای جداسازی ترکیبات بر اساس اختلاف قطبیت آن‌ها در یک ستون کروماتوگرافی استفاده می‌شود؟", "answer": "کروماتوگرافی مایع با کارایی بالا (HPLC) یا کروماتوگرافی ستونی."},
  {"question": "کاربرد اصلی دستگاه طیف‌سنجی مادون قرمز (IR Spectroscopy) چیست؟", "answer": "شناسایی گروه‌های عاملی موجود در یک مولکول با بررسی جذب نور مادون قرمز."},
  {"question": "چرا باید نمونه‌ها را قبل از ارسال به آزمایشگاه، به درستی برچسب‌گذاری کرد؟", "answer": "برای شناسایی دقیق نمونه، جلوگیری از اشتباه و اطمینان از ثبت صحیح نتایج."},
  {"question": "نام روشی برای اندازه‌گیری تراکم یا چگالی (Density) مایعات چیست؟", "answer": "هیدرومتر (Hydrometer) یا پیکنومتر (Pycnometer)."},
  {"question": "کدام تکنیک جداسازی برای جداسازی ذرات جامد از مایع با استفاده از نیروی گریز از مرکز است؟", "answer": "سانتریفیوژ (Centrifugation)."},
  {"question": "کاربرد اصلی دستگاه طیف‌سنجی جذب اتمی (AAS) چیست؟", "answer": "اندازه‌گیری غلظت فلزات در نمونه با اندازه‌گیری جذب نور توسط اتم‌های آزاد شده."},
  {"question": "چرا باید ابزار و تجهیزات آزمایشگاهی پس از اتمام کار تمیز و در جای خود قرار داده شوند؟", "answer": "برای نگهداری صحیح، جلوگیری از آسیب، آماده‌سازی برای استفاده بعدی و حفظ نظم آزمایشگاه."},
  {"question": "نام وسیله‌ای که برای هم زدن مداوم و یکنواخت مایعات استفاده می‌شود چیست؟", "answer": "همزن مغناطیسی (Magnetic Stirrer) یا همزن مکانیکی (Overhead Stirrer)."},
  {"question": "کدام تکنیک جداسازی برای جداسازی ترکیبات فرار از مخلوط در دمای اتاق با استفاده از اختلاف فشار بخار آن‌ها به کار می‌رود؟", "answer": "تبخیر (Evaporation) یا تقطیر خلاء (Vacuum Distillation)."},
  {"question": "کاربرد اصلی دستگاه الکتروفورز ژل (Gel Electrophoresis) چیست؟", "answer": "جداسازی قطعات DNA، RNA یا پروتئین‌ها بر اساس اندازه و بار الکتریکی آن‌ها."},
  {"question": "بزرگترین لایه زمین که بخش عمده‌ای از حجم آن را تشکیل می‌دهد چیست؟", "answer": "گوشته (Mantle)."},
  {"question": "کدام نوع سنگ از سرد شدن و انجماد ماگما یا گدازه به وجود می‌آید؟", "answer": "سنگ آذرین (Igneous Rock)."},
  {"question": "فرآیند فرسایش (Erosion) به چه معناست؟", "answer": "حمل و نقل مواد سنگی و خاکی توسط عوامل طبیعی مانند آب، باد و یخ."},
  {"question": "کدام مقیاس برای اندازه‌گیری شدت زلزله‌ها استفاده می‌شود؟", "answer": "مقیاس ریشتر (Richter Scale) یا مقیاس لرزه‌ای بزرگ (Magnitude Scale)."},
  {"question": "لایه‌ای از زمین که عمدتاً از آهن و نیکل مذاب تشکیل شده و میدان مغناطیسی زمین را تولید می‌کند چیست؟", "answer": "هسته خارجی (Outer Core)."},
  {"question": "کدام نوع سنگ از فشرده شدن و سیمانی شدن رسوبات (ذرات سنگی، بقایای گیاهی و جانوری) تشکیل می‌شود؟", "answer": "سنگ رسوبی (Sedimentary Rock)."},
  {"question": "کدام پدیده زمین‌شناسی باعث ایجاد کوه‌ها و دره‌های عمیق می‌شود؟", "answer": "حرکت و برخورد صفحات تکتونیکی (Plate Tectonics)."},
  {"question": "نام علم مطالعه چگونگی تشکیل، ترکیب و خواص سنگ‌ها چیست؟", "answer": "سنگ‌شناسی (Petrology)."},
  {"question": "کدام نوع سنگ در اثر حرارت و فشار بالا در اعماق زمین دگرگون می‌شود؟", "answer": "سنگ دگرگونی (Metamorphic Rock)."},
  {"question": "فرآیند ته‌نشینی (Deposition) به چه معناست؟", "answer": "قرار گرفتن و انباشته شدن ذرات رسوبی در یک محل توسط آب، باد یا یخ."},
  {"question": "نام بزرگترین صفحه تکتونیکی فعال در زمین چیست؟", "answer": "صفحه اقیانوس آرام (Pacific Plate)."},
  {"question": "کدام اصطلاح به لایه جامد و شکننده‌ی بیرونی زمین گفته می‌شود؟", "answer": "پوسته (Crust)."},
  {"question": "کدام نوع سنگ آذرین در سطح زمین و با سرعت زیاد سرد می‌شود؟", "answer": "سنگ آذرین بیرونی یا آتشفشانی (Extrusive/Volcanic Igneous Rock)."},
  {"question": "نام علم مطالعه لایه‌ها، ساختار و تاریخچه زمین چیست؟", "answer": "زمین‌شناسی (Geology)."},
  {"question": "کدام پدیده باعث ایجاد شکاف و فرو رفتگی در سطح زمین و گاهی فوران گدازه می‌شود؟", "answer": "فعالیت آتشفشانی (Volcanic Activity)."},
  {"question": "کدام اصطلاح به تمام آب‌های موجود در سیاره زمین (اقیانوس‌ها، دریاها، رودخانه‌ها، آب‌های زیرزمینی) اشاره دارد؟", "answer": "هیدروسفِر (Hydrosphere)."},
  {"question": "کدام نوع سنگ رسوبی از تجمع بقایای موجودات زنده (مانند صدف‌ها و اسکلت‌ها) تشکیل می‌شود؟", "answer": "سنگ کربناته (Carbonate Rock)، مانند سنگ آهک (Limestone)."},
  {"question": "فرآیند تبلور مجدد (Recrystallization) در کدام دسته از سنگ‌ها رخ می‌دهد؟", "answer": "سنگ‌های دگرگونی (Metamorphic Rocks)."},
  {"question": "نام علم مطالعه مواد معدنی، ترکیب، ساختار و خواص آن‌ها چیست؟", "answer": "کانی‌شناسی (Mineralogy)."},
  {"question": "کدام نوع سنگ آذرین در اعماق زمین و با سرعت کم سرد می‌شود؟", "answer": "سنگ آذرین درونی یا نفوذی (Intrusive/Plutonic Igneous Rock)."},
  {"question": "کدام اصطلاح به لایه‌های گازی اطراف زمین گفته می‌شود؟", "answer": "اتمسفر (Atmosphere)."},
  {"question": "کدام پدیده زمین‌شناسی باعث آزاد شدن ناگهانی انرژی ذخیره شده در پوسته زمین و ایجاد لرزش می‌شود؟", "answer": "زلزله (Earthquake)."},
  {"question": "کدام نوع سنگ رسوبی از فشرده شدن و سیمانی شدن ذرات خاک و رس تشکیل می‌شود؟", "answer": "سنگ شیل (Shale)."},
  {"question": "نام علم مطالعه بقایای موجودات زنده گذشته که در سنگ‌ها یافت می‌شوند چیست؟", "answer": "دیرینه‌شناسی (Paleontology)."},
  {"question": "کدام نوع سنگ دگرگونی از دگرگونی سنگ رسوبی شیل به وجود می‌آید؟", "answer": "سنگ لوح (Slate)."},
  {"question": "کدام اصطلاح به لایه‌های جامد، نیمه‌جامد و مذاب بالای پوسته زمین اشاره دارد؟", "answer": "گوشته (Mantle)."},
  {"question": "کدام نوع سنگ آذرین دارای بلورهای بزرگ و قابل مشاهده (مانند گرانیت) است؟", "answer": "سنگ آذرین درونی (Intrusive Igneous Rock)."},
  {"question": "فرآیند هوازدگی (Weathering) به چه معناست؟", "answer": "شکسته شدن و تجزیه سنگ‌ها در محل خودشان بدون جابجایی توسط عوامل فیزیکی، شیمیایی یا بیولوژیکی."},
  {"question": "کدام پدیده زمین‌شناسی باعث بالا آمدن ماگما از اعماق زمین و فوران آن به صورت گدازه می‌شود؟", "answer": "آتشفشان (Volcano)."},
  {"question": "کدام نوع سنگ رسوبی از ذرات ماسه تشکیل شده و سختی بالایی دارد؟", "answer": "سنگ ماسه‌سنگ (Sandstone)."},
  {"question": "نام علم مطالعه آب‌های زیرزمینی و نحوه حرکت و ذخیره شدن آن‌ها چیست؟", "answer": "آب زمین‌شناسی (Hydrogeology)."},
  {"question": "کدام نوع سنگ دگرگونی از دگرگونی سنگ آهک به وجود می‌آید؟", "answer": "سنگ مرمر (Marble)."},
  {"question": "کدام اصطلاح به بخش جامد و خارجی زمین (شامل پوسته و بخش بالایی گوشته) گفته می‌شود؟", "answer": "سنگ‌کره (Lithosphere)."},
  {"question": "کدام نوع سنگ آذرین دارای بلورهای ریز و گاهی شیشه‌ای (مانند بازالت) است؟", "answer": "سنگ آذرین بیرونی (Extrusive Igneous Rock)."},
  {"question": "کدام پدیده زمین‌شناسی باعث ایجاد چین‌خوردگی (Folding) در لایه‌های سنگی می‌شود؟", "answer": "نیروهای تکتونیکی فشاری."},
  {"question": "کدام نوع سنگ رسوبی از تبخیر آب شور و ته‌نشینی نمک‌ها به وجود می‌آید؟", "answer": "سنگ تبخیری (Evaporite Rock)، مانند هالیت (Halite)."},
  {"question": "نام علم مطالعه تغییرات آب و هوایی در گذشته زمین چیست؟", "answer": "پالئوکلیماتولوژی (Paleoclimatology)."},
  {"question": "کدام نوع سنگ دگرگونی از دگرگونی سنگ گرانیت به وجود می‌آید؟", "answer": "سنگ گنیس (Gneiss)."},
  {"question": "کدام اصطلاح به لایه‌های نرم و پلاستیک بالای گوشته که صفحات تکتونیکی روی آن حرکت می‌کنند، گفته می‌شود؟", "answer": "سست‌کره (Asthenosphere)."},
  {"question": "کدام نوع سنگ آذرین به دلیل ترکیب سیلیکاتی غنی و رنگ روشن شناخته می‌شود؟", "answer": "گرانیت (Granite)."},
  {"question": "کدام پدیده زمین‌شناسی باعث ایجاد شکستگی (Faulting) در لایه‌های سنگی و جابجایی آن‌ها می‌شود؟", "answer": "نیروهای تکتونیکی کششی یا فشاری."},
  {"question": "کدام نوع سنگ رسوبی از بقایای گیاهان پوسیده (مانند ذغال سنگ) تشکیل می‌شود؟", "answer": "سنگ‌های کربنی (Carbonaceous Rocks) یا زغال سنگ (Coal)."},
  {"question": "نام علم مطالعه تاریخچه زمین با استفاده از سنگ‌ها و فسیل‌ها چیست؟", "answer": "زمین‌شناسی تاریخی (Historical Geology)."},
  {"question": "کدام نوع سنگ دگرگونی از دگرگونی سنگ بازالت به وجود می‌آید؟", "answer": "سنگ شیست (Schist) یا سرپانتینیت (Serpentinite)."},
  {"question": "کدام اصطلاح به بخش مذاب و بسیار داغ مرکزی زمین اشاره دارد؟", "answer": "هسته (Core)."},
  {"question": "کدام نوع سنگ آذرین به دلیل ترکیب سیلیکاتی فقیر و رنگ تیره (مانند بازالت) شناخته می‌شود؟", "answer": "بازالت (Basalt)."},
  {"question": "کدام پدیده زمین‌شناسی باعث ایجاد حفره‌ها و غارهای زیرزمینی در سنگ‌های کربناته می‌شود؟", "answer": "انحلال (Dissolution) توسط آب‌های اسیدی (کارست)."},
  {"question": "کدام نوع سنگ رسوبی از ذرات کربن که در اثر فشار و حرارت حاصل شده‌اند، تشکیل می‌شود؟", "answer": "کربن (Carbon) یا زغال سنگ (Coal)."},
  {"question": "نام علم مطالعه کوه‌ها، فرآیندهای ایجاد کننده آن‌ها و اشکال سطحی آن‌ها چیست؟", "answer": "کوهزایی (Orogeny) یا مورفولوژی کوهستان."},
  {"question": "کدام نوع سنگ دگرگونی از دگرگونی سنگ کوارتزیت به وجود می‌آید؟", "answer": "کلاسیفیکاسیون مجدد کوارتزیت (Quartzite)."},
  {"question": "کدام پدیده تکتونیکی منجر به فرورانش (Subduction) یک صفحه اقیانوسی به زیر صفحه دیگر می‌شود؟", "answer": "همگرایی صفحات (Convergent Plate Boundary)."},
  {"question": "کدام نوع ناپیوستگی (Discontinuity) در سیاره زمین، مرز بین پوسته و گوشته بالایی را مشخص می‌کند؟", "answer": "ناپیوستگی موهوروویچیچ (Mohorovičić Discontinuity - Moho)."},
  {"question": "چه عاملی باعث ایجاد گنبد نمکی (Salt Dome) در حوضه‌های رسوبی می‌شود؟", "answer": "بالا آمدن نمک‌های سبک‌تر (Halokinesis) در اثر اختلاف چگالی و فشار، که لایه‌های بالایی را شکافته و بالا می‌زند."},
  {"question": "کدام نوع دگرگونی (Metamorphism) در اثر تماس سنگ‌ها با ماگمای داغ رخ می‌دهد؟", "answer": "دگرگونی مجاورتی (Contact Metamorphism)."},
  {"question": "نام فرآیند افزایش تدریجی دما با افزایش عمق در پوسته و گوشته زمین چیست؟", "answer": "گرادیان زمین‌گرمایی (Geothermal Gradient)."},
  {"question": "کدام نوع رانش (Mass Wasting) شامل حرکت سریع و ناگهانی توده‌ای از سنگ، خاک و یخ به سمت پایین دامنه است؟", "answer": "ریزشی (Rockfall) یا بهمن (Avalanche)."},
  {"question": "کدام منطقه یا کمربند زمین‌شناسی، محل تجمع غالب فعالیت‌های آتشفشانی و لرزه‌ای در اطراف حاشیه اقیانوس آرام است؟", "answer": "حلقه آتش اقیانوس آرام (Pacific Ring of Fire)."},
  {"question": "کدام نوع سنگ دگرگونی با بافتالصفحه‌ای (Foliated) مشخص می‌شود و از دگرگونی شیست به وجود می‌آید؟", "answer": "سنگ گنیس (Gneiss)."},
  {"question": "کدام نوع فوژ (Facies) رسوبی، نشان‌دهنده محیط‌های دریایی عمیق و دور از ساحل است؟", "answer": "فوژ پلژیک (Pelagic Facies)."},
  {"question": "نام فرآیند تشکیل کانی‌ها از محلول‌های آبی اشباع شده چیست؟", "answer": "تبلور (Crystallization)."},
  {"question": "کدام نوع مرز صفحه‌ای (Plate Boundary) با جدا شدن صفحات از یکدیگر و تشکیل پوسته جدید اقیانوسی مشخص می‌شود؟", "answer": "مرز واگرا (Divergent Plate Boundary)."},
  {"question": "کدام پدیده زمین‌شناسی باعث ایجاد درز و شکاف‌های عمیق در پوسته قاره‌ای می‌شود؟", "answer": "ریفتینگ (Rifting) یا گسل عادی (Normal Faulting)."},
  {"question": "نام علمی سنگ‌هایی که عمدتاً از کانی‌های گروه کوارتز و فلدسپات تشکیل شده‌اند چیست؟", "answer": "سنگ‌های سیلیکاتی (Silicate Rocks)."},
  {"question": "کدام نوع ناپیوستگی، مرز بین گوشته پایینی و هسته خارجی را مشخص می‌کند؟", "answer": "ناپیوستگی گوتنبرگ (Gutenberg Discontinuity)."},
  {"question": "کدام نوع دگرگونی در اثر فشار و تنش‌های منطقه‌ای وسیع، بدون افزایش قابل توجه دما رخ می‌دهد؟", "answer": "دگرگونی ناحیه‌ای (Regional Metamorphism)."},
  {"question": "نام پدیده‌ای که در آن مواد مذاب از اعماق گوشته به سطح زمین بالا آمده و باعث تشکیل جزایر آتشفشانی می‌شوند چیست؟", "answer": "نقطه داغ (Hotspot)."},
  {"question": "کدام نوع کانی دارای سختی ۱۰ در مقیاس موس است و به عنوان معیار سختی استفاده می‌شود؟", "answer": "الماس (Diamond)."},
  {"question": "کدام نوع فوژ (Facies) رسوبی، نشان‌دهنده محیط‌های رودخانه‌ای یا دلتایی است؟", "answer": "فوژ آلوویال (Alluvial Facies) یا فوژ دلتایی (Deltaic Facies)."},
  {"question": "کدام اصطلاح به تاریخچه و توالی رویدادهای زمین‌شناسی در یک منطقه خاص اشاره دارد؟", "answer": "چینه‌شناسی (Stratigraphy)."},
  {"question": "کدام نوع گسل (Fault) در اثر نیروهای کششی به وجود آمده و باعث کاهش ضخامت پوسته می‌شود؟", "answer": "گسل عادی (Normal Fault)."},
  {"question": "نام علم مطالعه رفتار مواد مذاب و فرآیندهای مرتبط با آن چیست؟", "answer": "ماگماتیسم (Magmatism) یا ولکانولوژی (Volcanology)."},
  {"question": "کدام پدیده زمین‌شناسی باعث تشکیل زنجیره‌های کوهستانی آتشفشانی در محل فرورانش صفحات می‌شود؟", "answer": "کمربندهای آتشفشانی قوسی (Volcanic Arcs)."},
  {"question": "کدام نوع دگرگونی در اثر شوک‌های ناشی از برخورد شهاب‌سنگ‌ها رخ می‌دهد؟", "answer": "دگرگونی برخوردی (Impact Metamorphism)."},
  {"question": "کدام فرآیند زمین‌شناسی باعث افزایش حجم و چگالی مواد در اعماق زمین و شکل‌گیری سنگ‌های دگرگونی می‌شود؟", "answer": "فشرده‌سازی (Compaction) و دگرگونی (Metamorphism)."},
  {"question": "نام پدیده‌ای که در آن مواد مذاب از شکاف‌های کف اقیانوس‌ها فوران کرده و پوسته جدید اقیانوسی را تشکیل می‌دهند چیست؟", "answer": "پهنک‌سازی کف اقیانوسی (Seafloor Spreading)."},
  {"question": "کدام نوع کانی‌ها گروه عمده‌ای از سنگ‌های سیلیسی را تشکیل می‌دهند و دارای ترکیب SiO2 هستند؟", "answer": "کانی‌های سیلیس (Silica Minerals)، مانند کوارتز (Quartz)."},
  {"question": "کدام نوع گسل در اثر نیروهای فشاری به وجود آمده و باعث افزایش ضخامت پوسته می‌شود؟", "answer": "گسل معکوس (Reverse Fault) یا گسل فشاری (Thrust Fault)."},
  {"question": "کدام پدیده تکتونیکی باعث بالا آمدن و چین خوردن لایه‌های رسوبی در مناطق همگرایی صفحات می‌شود؟", "answer": "کوهزایی (Orogeny)."},
  {"question": "نام علمی فرآیند بررسی و تعیین سن نسبی و مطلق سنگ‌ها و ساختارهای زمین‌شناسی چیست؟", "answer": "ژئوکرونولوژی (Geochronology)."},
  {"question": "کدام نوع فوژ (Facies) رسوبی، محیط‌های دریایی کم‌عمق و نزدیک به ساحل را نشان می‌دهد؟", "answer": "فوژ نریتیک (Neritic Facies)."},
  {"question": "چه قانونی بیان می‌کند که انرژی نه به وجود می‌آید و نه از بین می‌رود، بلکه فقط از شکلی به شکل دیگر تبدیل می‌شود؟", "answer": "قانون پایستگی انرژی (Law of Conservation of Energy)."},
  {"question": "چه پدیده‌ای باعث انحراف نور هنگام عبور از محیطی به محیط دیگر با چگالی متفاوت می‌شود؟", "answer": "شکست نور (Refraction)."},
  {"question": "کدام نظریه، گرانش را به عنوان خمیدگی فضا-زمان ناشی از جرم و انرژی توصیف می‌کند؟", "answer": "نظریه نسبیت عام اینشتین (Einstein's General Relativity)."},
  {"question": "چه نیرویی بین دو بار الکتریکی مشابه (مثبت-مثبت یا منفی-منفی) وارد می‌شود؟", "answer": "نیروی دافعه الکتریکی (Repulsive Electric Force)."},
  {"question": "چه مفهومی در مکانیک کوانتومی بیان می‌کند که نمی‌توان همزمان موقعیت و تکانه یک ذره را با دقت کامل دانست؟", "answer": "اصل عدم قطعیت هایزنبرگ (Heisenberg's Uncertainty Principle)."},
  {"question": "کدام نوع پیوند شیمیایی شامل اشتراک الکترون بین اتم‌ها برای رسیدن به پایداری است؟", "answer": "پیوند کووالانسی (Covalent Bond)."},
  {"question": "چه واکنشی گرماگیر است و برای ادامه به جذب انرژی از محیط نیاز دارد؟", "answer": "واکنش گرماگیر (Endothermic Reaction)."},
  {"question": "کدام قانون بیان می‌کند که در دمای ثابت، حجم معینی از گاز با فشار آن نسبت عکس دارد؟", "answer": "قانون بویل (Boyle's Law)."},
  {"question": "چه نوع ایزوتوپی از یک عنصر، تعداد نوترون‌های متفاوتی نسبت به ایزوتوپ مرجع دارد؟", "answer": "ایزوتوپ پرتوزا (Radioisotope)."},
  {"question": "نام کاتالیزوری که سرعت واکنش شیمیایی را بدون مصرف شدن در خود واکنش افزایش می‌دهد چیست؟", "answer": "کاتالیزور (Catalyst)."},
  {"question": "کدام اندامک سلولی مسئول فتوسنتز در سلول‌های گیاهی است؟", "answer": "کلروپلاست (Chloroplast)."},
  {"question": "چه فرآیندی در سلول‌ها، مولکول‌های کوچک را به مولکول‌های بزرگتر تبدیل می‌کند و به انرژی نیاز دارد؟", "answer": "فرایندهای آنابولیک (Anabolic Processes)."},
  {"question": "کدام نوع تقسیم سلولی منجر به تولید دو سلول دختری یکسان با تعداد کروموزوم‌های برابر با سلول مادر می‌شود؟", "answer": "میتوز (Mitosis)."},
  {"question": "چه مولکولی حامل اطلاعات ژنتیکی در اکثر موجودات زنده است؟", "answer": "دئوکسی ریبونوکلئیک اسید (DNA)."},
  {"question": "کدام نظریه بیان می‌کند که حیات از طریق تکامل تدریجی و انتخاب طبیعی از اشکال اولیه به وجود آمده است؟", "answer": "نظریه تکامل داروین (Darwin's Theory of Evolution)."},
  {"question": "چه پدیده‌ای باعث می‌شود که نور ستارگان دوردست هنگام عبور از اتمسفر زمین کمی پراکنده و جابجا شود؟", "answer": "چشمک زدن ستارگان (Scintillation)."},
  {"question": "نام سیاهچاله‌ای که در مرکز کهکشان راه شیری قرار دارد چیست؟", "answer": "کمان ای* (Sagittarius A*)."},
  {"question": "کدام فرضیه کیهان‌شناسی بیان می‌کند که جهان در حال انبساط است و از یک حالت بسیار داغ و متراکم اولیه آغاز شده است؟", "answer": "نظریه بیگ بنگ (Big Bang Theory)."},
  {"question": "چه نیرویی باعث می‌شود که سیارات به دور ستارگان خود در گردش باشند؟", "answer": "نیروی گرانش (Gravitational Force)."},
  {"question": "کدام پدیده کیهانی زمانی رخ می‌دهد که یک ستاره غول‌پیکر در پایان عمر خود منفجر می‌شود؟", "answer": "ابرنواختر (Supernova)."},
  {"question": "کدام فرآیند باعث فرسایش سنگ‌ها و تشکیل خاک در سطح زمین می‌شود؟", "answer": "هوازدگی (Weathering)."},
  {"question": "چه نوع لرزه‌خیزی در اثر حرکت ناگهانی صفحات تکتونیکی در طول گسل‌ها رخ می‌دهد؟", "answer": "زلزله تکتونیکی (Tectonic Earthquake)."},
  {"question": "نام لایه‌های مختلف اتمسفر زمین به ترتیب از پایین به بالا چیست؟", "answer": "تروپوسفر، استراتوسفر، مزوسفر، ترموسفر، اگزوسفر (Troposphere, Stratosphere, Mesosphere, Thermosphere, Exosphere)."},
  {"question": "کدام پدیده باعث گرم شدن زمین به دلیل جذب و بازتابش مجدد تابش‌های فروسرخ توسط گازهای گلخانه‌ای می‌شود؟", "answer": "اثر گلخانه‌ای (Greenhouse Effect)."},
  {"question": "کدام نوع فرآیند هوازدگی باعث تجزیه شیمیایی کانی‌ها و تغییر ترکیب شیمیایی آنها می‌شود؟", "answer": "هوازدگی شیمیایی (Chemical Weathering)."},
  {"question": "کدام شاخه از علم به مطالعه رفتار و برهم‌کنش مواد در مقیاس اتمی و مولکولی می‌پردازد؟", "answer": "شیمی فیزیک (Physical Chemistry)."},
  {"question": "نام علم مطالعه ذهن و رفتار انسان چیست؟", "answer": "روانشناسی (Psychology)."},
  {"question": "کدام شاخه از علم به مطالعه ساختار، ترکیب، و خواص مواد می‌پردازد؟", "answer": "علم مواد (Materials Science)."},
  {"question": "چه علم به مطالعه روابط بین موجودات زنده و محیط زیستشان می‌پردازد؟", "answer": "بوم‌شناسی (Ecology)."},
  {"question": "نام علم مطالعه حشرات چیست؟", "answer": "حشره‌شناسی (Entomology)."},
  {"question": "چه مفهومی در فیزیک کوانتومی، رفتار دوگانه موج-ذره را برای ذرات بنیادی توصیف می‌کند؟", "answer": "دوگانگی موج-ذره (Wave-Particle Duality)."},
  {"question": "کدام اصل در ترمودینامیک بیان می‌کند که آنتروپی یک سیستم ایزوله در طول زمان افزایش می‌یابد؟", "answer": "قانون دوم ترمودینامیک (Second Law of Thermodynamics)."},
  {"question": "نام واکنش شیمیایی که در آن یک مولکول بزرگ به واحدهای کوچکتر تجزیه می‌شود چیست؟", "answer": "واکنش تجزیه (Decomposition Reaction)."},
  {"question": "چه مفهومی در شیمی کوانتومی، تابع موجی را که حالت یک سیستم کوانتومی را توصیف می‌کند، ارائه می‌دهد؟", "answer": "معادله شرودینگر (Schrödinger Equation)."},
  {"question": "کدام فرآیند در باکتری‌ها، انرژی را از ترکیبات معدنی غیرآلی به دست می‌آورد؟", "answer": "شیمی‌سازی (Chemosynthesis)."},
  {"question": "نام اندامک سلولی که مسئول سنتز پروتئین‌ها است چیست؟", "answer": "ریبوزوم (Ribosome)."},
  {"question": "کدام پدیده زمین‌شناسی باعث ایجاد کوه‌هایی می‌شود که صفحات قاره‌ای با هم برخورد می‌کنند؟", "answer": "کوهزایی فشاری (Compressional Orogeny)."},
  {"question": "نام فرآیند چرخه آب در زمین چیست؟", "answer": "چرخه هیدرولوژیک (Hydrologic Cycle)."},
  {"question": "چه پدیده‌ای باعث می‌شود که ماده از یک ستاره دوتایی به ستاره دیگر کشیده شود؟", "answer": "انتقال جرم (Mass Transfer)."},
  {"question": "کدام ثابت کیهان‌شناسی، نرخ انبساط جهان را توصیف می‌کند؟", "answer": "ثابت هابل (Hubble Constant)."},
  {"question": "چه علم به مطالعه مبانی ریاضی و نظری رفتار سیستم‌های پیچیده می‌پردازد؟", "answer": "نظریه آشوب (Chaos Theory)."},
  {"question": "کدام حوزه علمی به بررسی تعاملات بین سیستم‌های بیولوژیکی و مهندسی می‌پردازد؟", "answer": "بیوتکنولوژی (Biotechnology)."},
  {"question": "نام علم مطالعه رفتار حیوانات چیست؟", "answer": "جانورشناسی رفتاری (Ethology)."},
  {"question": "کدام شاخه از علم به مطالعه ساختار و تاریخچه زمین با استفاده از فسیل‌ها می‌پردازد؟", "answer": "دیرینه‌شناسی (Paleontology)."},
