  {"question": "ساختار مولکولی متان (CH₄) چگونه است؟", "answer": "یک اتم کربن که به چهار اتم هیدروژن با پیوندهای کووالانسی مفرد در آرایش چهاروجهی پیوند خورده است."},
  {"question": "چرا مولکول متان چهاروجهی است؟", "answer": "به دلیل آرایش فضایی الکترون‌های اطراف اتم کربن (بر اساس نظریه VSEPR)."},
  {"question": "یک ترکیب یونی ساده را نام ببرید و ساختار آن را توضیح دهید.", "answer": "سدیم کلرید (NaCl)؛ شبکه‌ای بلوری که یون‌های Na⁺ و Cl⁻ به طور متناوب در آن قرار گرفته‌اند."},
  {"question": "تفاوت بین مولکول و ترکیب چیست؟", "answer": "مولکول کوچکترین واحد یک ماده است که خواص آن ماده را دارد، در حالی که ترکیب ماده‌ای است که از دو یا چند عنصر متفاوت تشکیل شده است."},
  {"question": "چگونه می‌توان ساختار یک مولکول را با استفاده از مدل‌های مولکولی نمایش داد؟", "answer": "با استفاده از توپ‌ها و چوب‌ها که اتم‌ها و پیوندها را نشان می‌دهند."},
  {"question": "ساختار مولکولی اکسیژن (O₂) چگونه است؟", "answer": "دو اتم اکسیژن که با یک پیوند کووالانسی دوگانه به هم متصل شده‌اند (O=O)."},
  {"question": "ساختار مولکولی نیتروژن (N₂) چگونه است؟", "answer": "دو اتم نیتروژن که با یک پیوند کووالانسی سه‌گانه به هم متصل شده‌اند (N≡N)."},
  {"question": "مفهوم الکترونگاتیویته چیست؟", "answer": "توانایی یک اتم برای جذب الکترون در یک پیوند شیمیایی."},
  {"question": "چگونه الکترونگاتیویته بر نوع پیوند تأثیر می‌گذارد؟", "answer": "اختلاف الکترونگاتیویته زیاد منجر به پیوند یونی، و اختلاف کم منجر به پیوند کووالانسی قطبی یا غیرقطبی می‌شود."},
  {"question": "ساختار مولکولی آمونیاک (NH₃) چگونه است؟", "answer": "یک اتم نیتروژن که به سه اتم هیدروژن با پیوندهای کووالانسی مفرد پیوند خورده است و مولکول هرمی شکل دارد."},
  {"question": "ساختار گرافیت و الماس (هر دو از کربن) چه تفاوتی دارند؟", "answer": "گرافیت لایه‌ای است و رسانای الکتریسیته، در حالی که الماس شبکه‌ای سه‌بعدی و بسیار سخت است."},
  {"question": "آهن چگونه از سنگ معدن استخراج می‌شود؟", "answer": "با ذوب کردن سنگ معدن آهن (مانند هماتیت) در کوره بلند با استفاده از کربن به عنوان عامل کاهنده."},
  {"question": "فرآیند تولید فولاد چیست؟", "answer": "ترکیب آهن با مقادیر کمی کربن و عناصر دیگر برای افزایش استحکام و خواص آن."},
  {"question": "چگونه مس از سنگ معدن آن به دست می‌آید؟", "answer": "با استخراج سنگ معدن مس و سپس استفاده از فرآیندهای الکترولیز یا ذوب برای خالص‌سازی آن."},
  {"question": "آلومینیوم چگونه تولید می‌شود؟", "answer": "از طریق الکترولیز اکسید آلومینیوم (آلومینا) که از بوکسیت استخراج می‌شود."},
  {"question": "چرا برخی فلزات مانند طلا و نقره خالص یافت می‌شوند؟", "answer": "به دلیل واکنش‌پذیری پایین آن‌ها، در طبیعت به صورت آزاد وجود دارند."},
  {"question": "چگونه می‌توان یک فلز را از ترکیبات یونی آن استخراج کرد؟", "answer": "با استفاده از روش‌هایی مانند الکترولیز یا کاهش شیمیایی."},
  {"question": "سنگ معدن چیست؟", "answer": "یک سنگ یا رسوب که حاوی مقادیر قابل توجهی از یک ماده معدنی یا فلز است که می‌توان آن را استخراج کرد."},
  {"question": "کانی چیست؟", "answer": "یک ماده معدنی جامد طبیعی با ساختار شیمیایی مشخص و خواص فیزیکی معین."},
  {"question": "چگونه سیمان ساخته می‌شود؟", "answer": "با حرارت دادن مخلوطی از سنگ آهک و رس در کوره و سپس آسیاب کردن کلینکر حاصل."},
  {"question": "شیشه از چه موادی ساخته می‌شود؟", "answer": "عمدتاً از ماسه (سیلیس)، سودا (کربنات سدیم) و آهک (کربنات کلسیم)."},
  {"question": "چگونه پلاستیک‌ها ساخته می‌شوند؟", "answer": "از طریق پلیمریزاسیون مونومرهای هیدروکربنی (محصولات نفتی)."},
  {"question": "کاغذ از چه ماده‌ای ساخته می‌شود؟", "answer": "از الیاف سلولزی که عمدتاً از چوب درختان به دست می‌آید."},
  {"question": "لاستیک طبیعی از کجا می‌آید؟", "answer": "از شیره یا لاتکس درختان کائوچو."},
  {"question": "چگونه فولاد ضد زنگ (Stainless Steel) ساخته می‌شود؟", "answer": "با اضافه کردن کروم و نیکل به آلیاژ آهن و کربن."},
  {"question": "نقش کاتالیزور در فرآیندهای صنعتی چیست؟", "answer": "افزایش سرعت واکنش بدون مصرف شدن در فرآیند."},
  {"question": "فرآیند تقطیر چه کاربردی در صنعت دارد؟", "answer": "برای جداسازی مایعات با نقاط جوش متفاوت، مانند جداسازی اجزای نفت خام."},
  {"question": "چگونه فلزات بازیافتی را می‌توان دوباره استفاده کرد؟", "answer": "با ذوب کردن و خالص‌سازی آن‌ها برای تولید محصولات جدید."},
  {"question": "چرا برخی فلزات زنگ می‌زنند (اکسید می‌شوند)؟", "answer": "به دلیل واکنش با اکسیژن و رطوبت در هوا."},
  {"question": "چگونه می‌توان از زنگ زدن فلزات جلوگیری کرد؟", "answer": "با پوشش دادن آن‌ها با رنگ، روغن، کروم یا ایجاد آلیاژهای مقاوم مانند فولاد ضد زنگ."},
  {"question": "چگونه شن و ماسه برای ساخت و ساز استفاده می‌شود؟", "answer": "به عنوان بخشی از بتن و ملات برای ایجاد استحکام."},
  {"question": "ساختار بلوری مواد جامد چگونه است؟", "answer": "اتم‌ها یا مولکول‌ها به صورت منظم و تکراری در یک شبکه سه‌بعدی چیده شده‌اند."},
  {"question": "چرا الماس سخت است و گرافیت نرم؟", "answer": "به دلیل تفاوت در ساختار شبکه‌ای اتم‌های کربن و نحوه پیوند آن‌ها."},
  {"question": "تفاوت بین جامد آمورف و جامد بلوری چیست؟", "answer": "در جامدات آمورف، اتم‌ها نظم بلندمدت ندارند، در حالی که در جامدات بلوری نظم دارند."},
  {"question": "چگونه می‌توانیم خواص یک ماده را با تغییر ساختار آن تغییر دهیم؟", "answer": "با تغییر نوع پیوند، چیدمان اتم‌ها یا افزودن عناصر دیگر (آلیاژسازی)."},
  {"question": "ساختار مولکولی بنزن (C₆H₆) را توضیح دهید.", "answer": "شش اتم کربن که یک حلقه شش‌ضلعی را تشکیل می‌دهند، با پیوندهای کووالانسی که به صورت رزونانس بین پیوند یگانه و دوگانه قرار دارند."},
  {"question": "چرا بنزن پایدار است؟", "answer": "به دلیل سیستم الکترونی پای (π) غیرمتمرکز (رزونانس)."},
  {"question": "چگونه فلزات گرما و الکتریسیته را هدایت می‌کنند؟", "answer": "به دلیل وجود الکترون‌های آزاد (دریاچه الکترونی) که قادر به حرکت در شبکه فلزی هستند."},
  {"question": "تفاوت بین رسانا، نیمه‌رسانا و عایق چیست؟", "answer": "بر اساس توانایی آن‌ها در هدایت الکتریسیته (هدایت بالا، متوسط، پایین)."},
  {"question": "چگونه می‌توانیم یک ماده جامد را به مایع تبدیل کنیم (ذوب)؟", "answer": "با افزودن انرژی گرمایی کافی برای غلبه بر نیروهای بین مولکولی."},
  {"question": "چگونه می‌توانیم یک مایع را به گاز تبدیل کنیم (تبخیر)؟", "answer": "با افزودن انرژی گرمایی کافی برای غلبه بر نیروهای بین مولکولی و فرار اتم‌ها/مولکول‌ها."},
  {"question": "ماگما و گدازه (لاوا) چه تفاوتی با یکدیگر دارند؟", "answer": "ماگما سنگی مذاب زیر سطح زمین است؛ گدازه همان ماگما پس از خروج به سطح زمین است."},
  {"question": "منشأ اصلی حرارت مورد نیاز برای ذوب شدن سنگ‌ها در گوشته چیست؟", "answer": "فروپاشی رادیواکتیو ایزوتوپ‌های سنگین و گرمای باقیمانده از تشکیل سیاره زمین."},
  {"question": "آیا تمام آتشفشان‌ها فوران می‌کنند؟", "answer": "خیر، برخی آتشفشان‌ها خاموش (Dormant) یا مرده (Extinct) هستند."},
  {"question": "فرضیه اصلی برای منشأ ماگما در مناطق آتشفشانی برداشتی (Divergent Boundaries) چیست؟", "answer": "کاهش فشار در نتیجه دور شدن صفحات تکتونیکی که باعث ذوب شدن بخشی از گوشته می‌شود."},
  {"question": "سه جزء اصلی تشکیل دهنده ماگما کدامند؟", "answer": "سیلیکات‌های مذاب (فاز مایع)، مواد معدنی بلوری (فاز جامد) و گازها (فاز گازی)."},
  {"question": "چگونه ویسکوزیته (گرانروی) ماگما بر نوع فوران تأثیر می‌گذارد؟", "answer": "ماگمای با ویسکوزیته بالا (غنی از سیلیس) فوران انفجاری ایجاد می‌کند، ماگمای با ویسکوزیته پایین فوران روان ایجاد می‌کند."},
  {"question": "تفاوت بین آتشفشان سپری و آتشفشان مخروطی مرکب (استراتووولکانو) چیست؟", "answer": "آتشفشان سپری شیب کمی دارد و از گدازه‌های روان تشکیل شده، در حالی که استراتووولکانو شیب تندی دارد و از لایه‌های گدازه و خاکستر ساخته شده است."},
  {"question": "مخروط آتشفشانی چیست؟", "answer": "توده‌ای از مواد آذرین (گدازه، خاکستر و سنگ‌ها) است که در اطراف دهانه آتشفشان جمع شده است."},
  {"question": "گدازه بازالتی چه ویژگی‌هایی دارد؟", "answer": "چسبندگی کم (ویسکوزیته پایین)، غنی از آهن و منیزیم، و معمولاً منجر به فوران‌های روان می‌شود."},
  {"question": "گدازه ریولیتیک چه ویژگی‌هایی دارد؟", "answer": "چسبندگی زیاد (ویسکوزیته بالا)، غنی از سیلیس، و معمولاً منجر به فوران‌های انفجاری می‌شود."},
  {"question": "پیامدهای فوران آتشفشانی غیر از جریان گدازه کدامند؟", "answer": "بارش خاکستر، جریان‌های پیروکلاستیک، و سونامی‌های آتشفشانی."},
  {"question": "جریان پیروکلاستیک چیست؟", "answer": "ابری داغ و سریع از گاز، خاکستر و سنگ که با سرعت بالا از آتشفشان سرازیر می‌شود و بسیار کشنده است."},
  {"question": "کالدیرا چیست؟", "answer": "فرورفتگی بزرگ و کاسه‌ای شکلی که پس از فروپاشی سقف محفظه ماگما پس از یک فوران بزرگ ایجاد می‌شود."},
  {"question": "پومیس (Pumice) چه نوع سنگی است و چگونه تشکیل می‌شود؟", "answer": "یک سنگ آذرین شیشه‌ای و بسیار متخلخل است که در اثر خروج سریع گازها از ماگمای بسیار ویسکوز تشکیل می‌شود."},
  {"question": "اثر اصلی گازهای آتشفشانی بر آب و هوای جهانی چیست؟", "answer": "انتشار دی‌اکسید گوگرد (SO₂) که می‌تواند به ذرات آئروسل تبدیل شده و نور خورشید را منعکس کند و باعث خنک شدن موقت شود."},
  {"question": "مناطق کانون‌های داغ (Hotspots) مانند هاوایی چگونه آتشفشان تشکیل می‌دهند؟", "answer": "در اثر بالا آمدن یک ستون گوشته‌ای ثابت (Plume) که صفحات در حال حرکت بر روی آن قرار دارند."},
  {"question": "گدازه آندزیتی معمولاً در کجا یافت می‌شود؟", "answer": "در نواحی فرورانش (Convergent Boundaries) جایی که صفحات اقیانوسی زیر قاره‌ای فرومی‌روند."},
  {"question": "مخروط خاکستری (Cinder Cone) کوچک‌ترین و ساده‌ترین نوع آتشفشان است. ویژگی آن چیست؟", "answer": "از پاشش قطرات گدازه به بیرون و فرود آمدن آن‌ها در اطراف دهانه، با شیب تند و عمر کوتاه، تشکیل می‌شود."},
  {"question": "اثرات بلندمدت فوران‌های بزرگ بر محیط زیست چیست؟", "answer": "تغییر در حاصلخیزی خاک به دلیل رسوب مواد معدنی، و تأثیرات اقلیمی."},
  {"question": "تفاوت اصلی بین ماگمای تولئیتیک و ماگمای قلیایی در چیست؟", "answer": "ماگمای تولئیتیک غنی‌تر از آهن و منیزیم و کم‌سیلیس‌تر است، در حالی که ماگمای قلیایی پتاسیم و سدیم بیشتری دارد."},
  {"question": "چرخه آب (هیدرولوژیک) چیست؟", "answer": "فرآیند مداوم حرکت آب در هیدروسفر زمین از طریق تبخیر، تعرق، میعان، بارش، رواناب و نفوذ."},
  {"question": "مراحل اصلی چرخه آب کدامند؟", "answer": "تبخیر/تعرق، میعان، بارش، نفوذ و رواناب سطحی."},
  {"question": "تبخیر چیست و چه عاملی باعث آن می‌شود؟", "answer": "تبدیل آب مایع به بخار آب؛ ناشی از انرژی خورشید."},
  {"question": "تعرق (Transpiration) به چه معناست؟", "answer": "آزاد شدن بخار آب از برگ گیاهان به اتمسفر."},
  {"question": "فرآیند میعان (Condensation) در چرخه آب چگونه رخ می‌دهد؟", "answer": "خنک شدن بخار آب در اتمسفر و تبدیل آن به قطرات مایع یا بلورهای یخ تشکیل دهنده ابر."},
  {"question": "بارش (Precipitation) شامل چه اشکالی است؟", "answer": "باران، برف، تگرگ و باران یخ زده."},
  {"question": "رواناب سطحی (Surface Runoff) چیست؟", "answer": "جریان آبی که پس از بارندگی بر روی سطح زمین حرکت کرده و به رودخانه‌ها و دریاچه‌ها می‌پیوندد."},
  {"question": "نفوذ (Infiltration) در چرخه آب به چه معناست؟", "answer": "حرکت آب از سطح زمین به درون خاک و لایه‌های زیرین."},
  {"question": "نقش اصلی انرژی خورشیدی در چرخه آب چیست؟", "answer": "تأمین انرژی لازم برای تبخیر آب از سطوح."},
  {"question": "چگونه ابرها تشکیل می‌شوند؟", "answer": "با صعود هوای مرطوب، سرد شدن آن تا رسیدن به نقطه شبنم و میعان بخار آب به دور هسته‌های میعان."},
  {"question": "چرا برخی از بخار آب مستقیماً به یخ تبدیل می‌شود بدون اینکه مایع شود؟", "answer": "به این فرآیند تصعید معکوس (Deposition) گفته می‌شود و در دماهای زیر انجماد رخ می‌دهد."},
  {"question": "فرآیند فروریزش (Sublimation) در چرخه آب چیست؟", "answer": "تبدیل مستقیم یخ یا برف به بخار آب بدون عبور از فاز مایع."},
  {"question": "آبخوان (Aquifer) چیست؟", "answer": "یک لایه زیرزمینی از سنگ یا رسوبات که به اندازه کافی نفوذپذیر است و می‌تواند آب را ذخیره کرده و منتقل کند."},
  {"question": "سقف آب (Water Table) به چه ارتفاعی اطلاق می‌شود؟", "answer": "مرز بالایی ناحیه اشباع آب زیر سطح زمین."},
  {"question": "آب زیرزمینی چگونه دوباره به سطح زمین برمی‌گردد؟", "answer": "از طریق چشمه‌ها، چاه‌ها، یا جریان‌یابی به رودخانه‌ها و دریاچه‌ها."},
  {"question": "نفوذ عمقی (Percolation) چیست؟", "answer": "حرکت آب به سمت پایین از طریق لایه‌های زیرین زمین پس از نفوذ اولیه."},
  {"question": "نقش پوشش گیاهی (جنگل‌ها) در مدیریت چرخه آب چیست؟", "answer": "افزایش نفوذ آب، کاهش رواناب سطحی و کاهش فرسایش خاک."},
  {"question": "آیا رودخانه‌ها فقط از طریق باران تغذیه می‌شوند؟", "answer": "خیر، آن‌ها اغلب از طریق جریان آب زیرزمینی (Baseflow) نیز تغذیه می‌شوند."},
  {"question": "چرا در مناطق خشک، فرسایش بادی اهمیت بیشتری نسبت به فرسایش آبی دارد؟", "answer": "به دلیل کمبود پوشش گیاهی و کاهش رواناب سطحی مؤثر."},
  {"question": "آب زیرزمینی به چه معناست؟", "answer": "آبی که در فضاهای خالی بین ذرات سنگ‌ها و رسوبات زیر سطح زمین به دام افتاده است."},
  {"question": "انواع ذخایر آب در زمین را به دو دسته اصلی تقسیم کنید.", "answer": "ذخایر آب سطحی (رودخانه‌ها، دریاچه‌ها، یخچال‌ها) و ذخایر آب زیرزمینی (آبخوان‌ها)."},
  {"question": "یخچال‌های طبیعی چه سهمی از آب شیرین جهان را دارند؟", "answer": "بیش از دو سوم آب شیرین جهان را به صورت یخ ذخیره کرده‌اند."},
  {"question": "بزرگترین ذخیره آب شیرین جهان کجاست؟", "answer": "یخچال‌های قطبی و کوهستانی."},
  {"question": "بزرگترین ذخیره آب مایع جهان کجاست؟", "answer": "اقیانوس‌ها (آب شور)، و پس از آن آب‌های زیرزمینی."},
  {"question": "تفاوت بین آبخوان آزاد (Unconfined) و آبخوان محصور (Confined) چیست؟", "answer": "آبخوان آزاد توسط لایه نفوذناپذیر در بالا محدود نشده است، در حالی که آبخوان محصور بین دو لایه نفوذناپذیر قرار دارد."},
  {"question": "چشمه آرتزین (Artesian Well) چگونه شکل می‌گیرد؟", "answer": "زمانی که یک چاه در یک آبخوان محصور حفر می‌شود و سطح آب آزاد (Potentiometric Surface) بالاتر از سطح زمین باشد."},
  {"question": "سطح پتانسیومتری (Potentiometric Surface) در یک آبخوان محصور چیست؟", "answer": "ارتفاعی که آب در چاه به آن سطح می‌رسد، که نشان دهنده فشار هیدرواستاتیک آب در آبخوان است."},
  {"question": "تفاوت بین منطقه اشباع (Saturated Zone) و منطقه هوادار (Vadose Zone) چیست؟", "answer": "منطقه اشباع جایی است که تمام فضاهای خالی با آب پر شده‌اند، و منطقه هوادار فضایی بالای آن است که هوا نیز در آن وجود دارد."},
  {"question": "آب زیرزمینی چگونه می‌تواند آلوده شود؟", "answer": "از طریق نفوذ آلاینده‌ها از دفن زباله، استفاده از کودها و آفت‌کش‌ها، یا نفوذ پساب‌های صنعتی."},
  {"question": "حوضه آبریز (Watershed) چیست؟", "answer": "منطقه‌ای زمینی که تمام آب‌های سطحی آن به یک نقطه مشترک (مانند رودخانه یا دریاچه) تخلیه می‌شوند."},
  {"question": "رودخانه چه نقشی در انتقال آب و انرژی دارد؟", "answer": "انتقال آب شیرین از خشکی به دریاها و اقیانوس‌ها، و همچنین انتقال رسوبات و مواد مغذی."},
  {"question": "دریاچه‌ها چگونه از نظر زمین‌شناسی شکل می‌گیرند؟", "answer": "از طریق یخچال‌های طبیعی، فعالیت‌های آتشفشانی، یا فرسایش رودخانه‌ای و باد."},
  {"question": "چرا منابع آب زیرزمینی اغلب منبع پایدارتری نسبت به آب‌های سطحی هستند؟", "answer": "به دلیل محافظت شدن از تبخیر مستقیم و آلودگی‌های سطحی."},
  {"question": "فرونشست زمین (Land Subsidence) چگونه می‌تواند با برداشت بیش از حد آب زیرزمینی مرتبط باشد؟", "answer": "برداشت زیاد باعث از دست رفتن تکیه‌گاه هیدرواستاتیکی شده و لایه‌های رسوبی فشرده می‌شوند."},
  {"question": "اهمیت چشمه‌ها (Springs) در جوامع انسانی چیست؟", "answer": "به عنوان منابع طبیعی و پایدار آب آشامیدنی و کشاورزی در طول تاریخ."},
  {"question": "چرا آب زیرزمینی اغلب طعم معدنی (سختی) دارد؟", "answer": "به دلیل حل شدن مواد معدنی مانند کلسیم و منیزیم از سنگ‌های اطراف هنگام نفوذ آب."},
  {"question": "مفهوم ذخایر آب فسیلی (Fossil Water) چیست؟", "answer": "آب‌های زیرزمینی که هزاران سال پیش جمع شده‌اند و نرخ تغذیه مجدد آن‌ها بسیار کند است."},
  {"question": "تفاوت ذخایر آب شیرین سطحی و زیرزمینی در پایداری بهره‌برداری چیست؟", "answer": "آب‌های سطحی به شدت وابسته به بارندگی‌های اخیر هستند، در حالی که آب‌های زیرزمینی به عنوان یک بافر عمل می‌کنند."},
  {"question": "چرا فاضلاب شهری باید قبل از بازگشت به آب‌های سطحی تصفیه شود؟", "answer": "برای حذف آلاینده‌های آلی و معدنی و جلوگیری از اثرات نامطلوب بر اکوسیستم آبی."},
  {"question": "نقش تالاب‌ها (Wetlands) در چرخه آب چیست؟", "answer": "عملکرد به عنوان اسفنج‌های طبیعی، کنترل سیلاب، تصفیه طبیعی آب و ذخیره‌سازی موقت آب."},
  {"question": "منظور از بازچرخانی آب (Water Recycling) در مدیریت منابع چیست؟", "answer": "تصفیه و استفاده مجدد از فاضلاب یا پساب برای کاربردهای غیرآشامیدنی مانند آبیاری."},
  {"question": "کدام فرآیند در چرخه آب، منبع اصلی رطوبت جو است؟", "answer": "تبخیر و تعرق."},
  {"question": "چرا در مناطق کوهستانی، بارش برف نقش مهمی در تأمین آب رودخانه‌ها در طول سال دارد؟", "answer": "برف به صورت یک ذخیره کننده فصلی عمل می‌کند و آب را به تدریج از طریق ذوب شدن در فصول گرم آزاد می‌کند."},
  {"question": "آبخوان آرتزین (Artesian Aquifer) در کدام دسته از آبخوان‌ها قرار می‌گیرد؟", "answer": "آبخوان محصور (Confined Aquifer)."},
  {"question": "چگونه می‌توان میزان نفوذپذیری یک خاک را تعیین کرد؟", "answer": "از طریق آزمایش نفوذسنجی (Permeability Test) در محل."},
  {"question": "اثر گرمایش جهانی بر چرخه آب چیست؟", "answer": "افزایش نرخ تبخیر، افزایش شدت بارش‌ها و تغییر توزیع فضایی و زمانی منابع آب."},
  {"question": "رابطه بین نفوذ و فرسایش چیست؟", "answer": "افزایش نفوذ باعث کاهش رواناب سطحی و در نتیجه کاهش فرسایش خاک می‌شود."},
  {"question": "چرا در مناطق بیابانی، آب‌های زیرزمینی معمولاً نمکی‌تر هستند؟", "answer": "به دلیل تبخیر شدید سطحی و بالا آمدن نمک‌ها از طریق مویینگی و تبلور مجدد."},
  {"question": "آیا آب‌های زیرزمینی در حال تجدید هستند؟", "answer": "بله، آب‌هایی که در ناحیه هوادار نفوذ کرده و به سطح آبخوان می‌رسند، در حال تجدید هستند؛ اما برخی قدیمی‌ترها نیستند."},
  {"question": "انرژی چیست؟", "answer": "انرژی به توانایی انجام کار گفته می‌شود و شکلی از وجود است که می‌تواند به اشکال دیگر تبدیل شود."},
  {"question": "قانون پایستگی انرژی چیست؟", "answer": "قانون پایستگی انرژی بیان می‌کند که انرژی نه به وجود می‌آید و نه از بین می‌رود، بلکه تنها از شکلی به شکل دیگر تبدیل می‌شود."},
  {"question": "انرژی مکانیکی شامل چه اجزایی است؟", "answer": "انرژی مکانیکی شامل انرژی جنبشی (مرتبط با حرکت) و انرژی پتانسیل (مرتبط با موقعیت یا وضعیت) است."},
  {"question": "انرژی جنبشی چیست؟", "answer": "انرژی جنبشی انرژی است که یک جسم به دلیل حرکت خود دارد."},
  {"question": "فرمول انرژی جنبشی چیست؟", "answer": "فرمول انرژی جنبشی برابر است با: \$KE = 1/2 * m * v^2\$ که در آن m جرم و v سرعت است."},
  {"question": "انرژی پتانسیل چیست؟", "answer": "انرژی پتانسیل انرژی ذخیره شده در یک جسم به دلیل موقعیت، وضعیت یا ترکیب آن است."},
  {"question": "انواع انرژی پتانسیل را نام ببرید.", "answer": "انواع رایج انرژی پتانسیل عبارتند از: گرانشی، کشسانی (مانند فنر) و شیمیایی."},
  {"question": "انرژی گرمایی (حرارتی) چیست؟", "answer": "انرژی گرمایی انرژی درونی یک ماده است که به حرکت تصادفی اتم‌ها و مولکول‌های آن مربوط می‌شود."},
  {"question": "دمای یک جسم چگونه با انرژی گرمایی آن ارتباط دارد؟", "answer": "دمای بالاتر نشان‌دهنده حرکت سریع‌تر ذرات و در نتیجه انرژی گرمایی بیشتر است."},
  {"question": "انرژی الکتریکی چیست؟", "answer": "انرژی الکتریکی شکلی از انرژی است که به حرکت بار الکتریکی (جریان الکتریکی) یا تجمع بار الکتریکی (بار الکتریکی ساکن) مربوط می‌شود."},
  {"question": "چگونه انرژی الکتریکی تولید می‌شود؟", "answer": "انرژی الکتریکی معمولاً با تبدیل اشکال دیگر انرژی (مانند مکانیکی، شیمیایی، هسته‌ای) در ژنراتورها تولید می‌شود."},
  {"question": "انرژی هسته‌ای چیست؟", "answer": "انرژی هسته‌ای انرژی است که در هسته اتم‌ها ذخیره شده و با واکنش‌های هسته‌ای مانند شکافت یا همجوشی آزاد می‌شود."},
  {"question": "شکافت هسته‌ای چیست؟", "answer": "شکافت هسته‌ای فرآیندی است که در آن هسته یک اتم سنگین به هسته‌های کوچک‌تر تقسیم می‌شود و مقدار زیادی انرژی آزاد می‌کند."},
  {"question": "همجوشی هسته‌ای چیست؟", "answer": "همجوشی هسته‌ای فرآیندی است که در آن هسته‌های اتم‌های سبک با هم ترکیب شده و هسته سنگین‌تری را تشکیل می‌دهند و انرژی عظیمی آزاد می‌کنند (مانند آنچه در خورشید رخ می‌دهد)."},
  {"question": "انرژی تابشی چیست؟", "answer": "انرژی تابشی شکلی از انرژی است که به صورت امواج الکترومغناطیسی (مانند نور مرئی، فروسرخ، فرابنفش، اشعه ایکس) منتشر می‌شود."},
  {"question": "مثال‌هایی از انرژی تابشی را بزنید.", "answer": "نور خورشید، امواج رادیویی، گرمای حاصل از آتش، نور لامپ همگی نمونه‌هایی از انرژی تابشی هستند."},
  {"question": "کار (Work) در فیزیک به چه معناست؟", "answer": "کار زمانی انجام می‌شود که نیرویی بر روی یک جسم وارد شود و باعث جابجایی آن جسم در راستای نیرو شود."},
  {"question": "فرمول کار چیست؟", "answer": "فرمول کار برابر است با: \$W = F * d * cos(theta)\$ که در آن F نیرو، d جابجایی و theta زاویه بین نیرو و جابجایی است."},
  {"question": "توان (Power) چیست؟", "answer": "توان نرخ انجام کار یا نرخ انتقال انرژی است."},
  {"question": "فرمول توان چیست؟", "answer": "فرمول توان برابر است با: \$P = W / t\$ که در آن W کار انجام شده و t زمان است، یا \$P = E / t\$ که در آن E انرژی منتقل شده است."},
  {"question": "واحد اندازه‌گیری کار چیست؟", "answer": "واحد اندازه‌گیری کار در سیستم SI، ژول (Joule) است."},
  {"question": "واحد اندازه‌گیری توان چیست؟", "answer": "واحد اندازه‌گیری توان در سیستم SI، وات (Watt) است. یک وات برابر با یک ژول بر ثانیه است."},
  {"question": "راندمان (Efficiency) چیست؟", "answer": "راندمان نسبت انرژی مفید خروجی یک سیستم به کل انرژی ورودی آن است و معمولاً به صورت درصد بیان می‌شود."},
  {"question": "چرا راندمان هیچ سیستمی ۱۰۰٪ نیست؟", "answer": "به دلیل اتلاف انرژی به اشکال دیگر مانند گرما، صدا یا اصطکاک در فرآیند تبدیل انرژی."},
  {"question": "مثال تبدیل انرژی را بزنید.", "answer": "تبدیل انرژی شیمیایی در غذا به انرژی مکانیکی در بدن هنگام دویدن."},
  {"question": "چگونه یک لامپ رشته‌ای انرژی را تبدیل می‌کند؟", "answer": "لامپ رشته‌ای انرژی الکتریکی را عمدتاً به انرژی گرمایی (نور و گرما) تبدیل می‌کند و راندمان پایینی دارد."},
  {"question": "لامپ LED چگونه انرژی را تبدیل می‌کند؟", "answer": "لامپ LED انرژی الکتریکی را به نور تبدیل می‌کند و راندمان بسیار بالاتری نسبت به لامپ رشته‌ای دارد."},
  {"question": "تبدیل انرژی در پنکه چگونه است؟", "answer": "پنکه انرژی الکتریکی را به انرژی مکانیکی (حرکت پره‌ها) تبدیل می‌کند."},
  {"question": "تبدیل انرژی در سشوار چگونه است؟", "answer": "سشوار انرژی الکتریکی را به انرژی گرمایی (برای گرم کردن هوا) و انرژی مکانیکی (برای باد زدن) تبدیل می‌کند."},
  {"question": "انرژی پتانسیل گرانشی به چه عواملی بستگی دارد؟", "answer": "انرژی پتانسیل گرانشی به جرم جسم، ارتفاع آن از سطح مرجع و شتاب گرانش بستگی دارد."},
  {"question": "فرمول انرژی پتانسیل گرانشی چیست؟", "answer": "فرمول انرژی پتانسیل گرانشی برابر است با: \$PE = m * g * h\$ که در آن m جرم، g شتاب گرانش و h ارتفاع است."},
  {"question": "انرژی شیمیایی چگونه ذخیره می‌شود؟", "answer": "انرژی شیمیایی در پیوندهای بین اتم‌ها در مولکول‌ها ذخیره می‌شود."},
  {"question": "هنگام سوختن چوب چه اتفاقی برای انرژی می‌افتد؟", "answer": "انرژی شیمیایی ذخیره شده در چوب به انرژی گرمایی و تابشی تبدیل می‌شود."},
  {"question": "انرژی کشسانی چیست؟", "answer": "انرژی کشسانی، انرژی ذخیره شده در اجسام الاستیک (مانند فنر یا کش) هنگامی که کشیده یا فشرده می‌شوند."},
  {"question": "فرمول انرژی پتانسیل کشسانی یک فنر چیست؟", "answer": "فرمول انرژی پتانسیل کشسانی یک فنر برابر است با: \$PE_s = 1/2 * k * x^2\$ که در آن k ثابت فنر و x جابجایی از نقطه تعادل است."},
  {"question": "انرژی صوتی چیست؟", "answer": "انرژی صوتی شکلی از انرژی است که از طریق ارتعاشات در یک محیط (مانند هوا، آب، جامدات) منتقل می‌شود."},
  {"question": "انرژی الکترومغناطیسی چیست؟", "answer": "انرژی الکترومغناطیسی شکلی از انرژی است که به صورت امواج الکترومغناطیسی منتقل می‌شود و شامل طیف وسیعی از تابش‌ها است."},
  {"question": "تفاوت انرژی و توان را با یک مثال توضیح دهید.", "answer": "اگر یک وزنه ۱۰۰ کیلوگرمی را ۱۰ متر بالا ببرید، کار یکسانی انجام داده‌اید (انرژی مصرف شده)، اما اگر این کار را در ۱ دقیقه انجام دهید توان بیشتری نسبت به زمانی که در ۱۰ دقیقه انجام دهید، مصرف کرده‌اید."},
  {"question": "نقش اصطکاک در تبدیل انرژی چیست؟", "answer": "اصطکاک معمولاً باعث اتلاف انرژی به صورت گرما می‌شود و راندمان فرآیندهای تبدیل انرژی را کاهش می‌دهد."},
  {"question": "انرژی در سیستم‌های بیولوژیکی چگونه جریان دارد؟", "answer": "در سیستم‌های بیولوژیکی، انرژی معمولاً از طریق فتوسنتز (توسط گیاهان) یا مصرف مواد غذایی (توسط جانوران) وارد شده و از طریق واکنش‌های شیمیایی مانند تنفس سلولی آزاد و تبدیل می‌شود."},
  {"question": "فتوسنتز چیست و چه نوع انرژی را به چه نوع انرژی تبدیل می‌کند؟", "answer": "فتوسنتز فرآیندی است که در آن گیاهان انرژی تابشی خورشید را به انرژی شیمیایی ذخیره شده در مولکول‌های قند تبدیل می‌کنند."},
  {"question": "تنفس سلولی چیست و چه نوع انرژی را به چه نوع انرژی تبدیل می‌کند؟", "answer": "تنفس سلولی فرآیندی است که در آن انرژی شیمیایی ذخیره شده در مولکول‌های مواد غذایی (مانند گلوکز) به انرژی قابل استفاده سلول (ATP) تبدیل می‌شود."},
  {"question": "اثر گلخانه‌ای چه ارتباطی با انرژی دارد؟", "answer": "اثر گلخانه‌ای به دلیل جذب و بازتابش انرژی تابشی خورشید توسط گازهای گلخانه‌ای در اتمسفر رخ می‌دهد که باعث گرم شدن زمین می‌شود."},
  {"question": "چرا در زمستان احساس سرما می‌کنیم؟", "answer": "در زمستان، زمین انرژی تابشی کمتری از خورشید دریافت می‌کند و اتلاف انرژی گرمایی از سطح زمین به فضا افزایش می‌یابد، که منجر به کاهش دما می‌شود."},
  {"question": "انتقال انرژی چگونه در فضا انجام می‌شود؟", "answer": "انتقال انرژی در فضا عمدتاً از طریق تابش الکترومغناطیسی انجام می‌شود، زیرا فضا خلاء است و رسانش یا همرفت در آن صورت نمی‌گیرد."},
  {"question": "حرارت چیست و چگونه منتقل می‌شود؟", "answer": "حرارت شکل انتقال انرژی گرمایی است که به طور طبیعی از جسم گرم‌تر به جسم سردتر منتقل می‌شود. سه روش اصلی انتقال حرارت عبارتند از: رسانش، همرفت و تابش."},
  {"question": "رسانش (Conduction) چیست؟", "answer": "رسانش انتقال گرما از طریق برخورد مستقیم ذرات ماده است، معمولاً در جامدات رخ می‌دهد."},
  {"question": "همرفت (Convection) چیست؟", "answer": "همرفت انتقال گرما از طریق جابجایی (حرکت) سیالات (مایعات و گازها) است."},
  {"question": "تابش (Radiation) چیست؟", "answer": "تابش انتقال گرما از طریق امواج الکترومغناطیسی است و نیازی به محیط مادی ندارد."},
  {"question": "مثالی از رسانش گرما بزنید.", "answer": "وقتی یک انتهای قاشق فلزی را در چای داغ قرار می‌دهید، انتهای دیگر آن نیز پس از مدتی گرم می‌شود (رسانش)."},
  {"question": "مثالی از همرفت گرما بزنید.", "answer": "گرم شدن آب در کتری؛ آب داغ که چگالی کمتری دارد به سمت بالا حرکت کرده و آب سرد جایگزین آن می‌شود."},
  {"question": "مثالی از تابش گرما بزنید.", "answer": "گرمایی که از خورشید به زمین می‌رسد یا گرمایی که از یک آتش احساس می‌کنید."},
  {"question": "چگونه یک ترموس (قمقمه) اتلاف انرژی را کاهش می‌دهد؟", "answer": "تروموس با استفاده از دیواره‌های دوجداره خلاء بین آن‌ها (برای کاهش رسانش و همرفت) و سطح بازتابنده (برای کاهش تابش) اتلاف انرژی را به حداقل می‌رساند."},
  {"question": "چرا فلزات رسانای خوبی برای گرما هستند؟", "answer": "به دلیل وجود الکترون‌های آزاد در ساختار فلزات که به سرعت انرژی را منتقل می‌کنند."},
  {"question": "چرا هوا یک رسانای ضعیف گرما است؟", "answer": "به دلیل فاصله زیاد بین مولکول‌های هوا و حرکت تصادفی آن‌ها."},
  {"question": "اهمیت قانون اول ترمودینامیک (پایستگی انرژی) در مهندسی چیست؟", "answer": "این قانون اساس طراحی تمام سیستم‌های تبدیل انرژی است و تضمین می‌کند که انرژی در هیچ فرآیندی گم نمی‌شود."},
  {"question": "چگونه انرژی پتانسیل به انرژی جنبشی تبدیل می‌شود؟", "answer": "هنگامی که یک جسم در میدان گرانشی سقوط می‌کند، انرژی پتانسیل گرانشی آن به انرژی جنبشی تبدیل می‌شود."},
  {"question": "مثال تبدیل انرژی پتانسیل به جنبشی در زندگی روزمره چیست؟", "answer": "هنگامی که یک توپ را رها می‌کنید، انرژی پتانسیل آن به انرژی جنبشی تبدیل می‌شود."},
  {"question": "انرژی در سیستم‌های الکترونیکی چگونه است؟", "answer": "انرژی الکترونیکی شامل انرژی پتانسیل الکتریکی (ولتاژ) و انرژی جنبشی الکترون‌ها (جریان) است."},
  {"question": "دستگاه‌های الکترونیکی چگونه انرژی را مصرف می‌کنند؟", "answer": "این دستگاه‌ها انرژی الکتریکی را به اشکال دیگر مانند نور (صفحه نمایش)، صدا (بلندگو)، گرما (پردازنده) یا انجام کار (موتور) تبدیل می‌کنند."},
  {"question": "منظور از 'انرژی پایدار' چیست؟", "answer": "انرژی پایدار به انرژی گفته می‌شود که از منابع تجدیدپذیر به دست می‌آید و اثرات زیست‌محیطی و اجتماعی منفی کمی دارد."},
  {"question": "تفاوت بین انرژی تجدیدپذیر و تجدیدناپذیر چیست؟", "answer": "منابع تجدیدپذیر (مانند خورشید، باد، آب) به طور طبیعی در مقیاس زمانی انسان بازسازی می‌شوند، در حالی که منابع تجدیدناپذیر (مانند سوخت‌های فسیلی) محدود هستند و پس از مصرف جایگزین نمی‌شوند."},
  {"question": "چرخه سوخت فسیلی شامل چه مراحلی است؟", "answer": "استخراج، پالایش، حمل و نقل و احتراق."},
  {"question": "تبدیل انرژی در یک توربین بادی چگونه است؟", "answer": "انرژی جنبشی باد به انرژی مکانیکی (چرخش پره‌ها) و سپس توسط ژنراتور به انرژی الکتریکی تبدیل می‌شود."},
  {"question": "تبدیل انرژی در یک پنل خورشیدی چگونه است؟", "answer": "انرژی تابشی خورشید به طور مستقیم توسط سلول‌های فتوولتائیک به انرژی الکتریکی تبدیل می‌شود."},
  {"question": "سوخت چیست؟", "answer": "سوخت ماده‌ای است که هنگام سوختن (اکسید شدن) انرژی قابل توجهی را به صورت گرما و نور آزاد می‌کند."},
  {"question": "مهم‌ترین انواع سوخت‌های فسیلی کدامند؟", "answer": "زغال سنگ، نفت خام و گاز طبیعی."},
  {"question": "چرا سوخت‌های فسیلی 'فسیلی' نامیده می‌شوند؟", "answer": "زیرا از بقایای تجزیه شده گیاهان و جانوران باستانی که طی میلیون‌ها سال تحت فشار و حرارت دفن شده‌اند، به وجود آمده‌اند."},
  {"question": "مزایای استفاده از سوخت‌های فسیلی چیست؟", "answer": "چگالی انرژی بالا، سهولت حمل و نقل و ذخیره‌سازی، زیرساخت‌های موجود برای استفاده گسترده."},
  {"question": "معایب استفاده از سوخت‌های فسیلی چیست؟", "answer": "تولید گازهای گلخانه‌ای (مانند CO2) و آلاینده‌های هوا، محدود بودن منابع، خطرات زیست‌محیطی استخراج و حمل و نقل."},
  {"question": "اثرات انتشار CO2 ناشی از سوخت‌های فسیلی چیست؟", "answer": "گرمایش جهانی، تغییرات اقلیمی، اسیدی شدن اقیانوس‌ها."},
  {"question": "نفت خام چیست و چگونه فرآوری می‌شود؟", "answer": "نفت خام مخلوط پیچیده‌ای از هیدروکربن‌هاست که در پالایشگاه‌ها به محصولاتی مانند بنزین، گازوئیل، نفت سفید و پلاستیک تبدیل می‌شود."},
  {"question": "گاز طبیعی چیست و عمدتاً از چه گازی تشکیل شده است؟", "answer": "گاز طبیعی عمدتاً از متان (CH4) تشکیل شده و به عنوان سوخت پاک‌تر نسبت به زغال سنگ و نفت در نظر گرفته می‌شود."},
  {"question": "زغال سنگ چیست و چه انواعی دارد؟", "answer": "زغال سنگ یک سنگ رسوبی قابل اشتعال است که عمدتاً از کربن تشکیل شده. انواع اصلی آن عبارتند از: لیگنیت، ساب‌بیتومینس، بیتومینس و آنتراسیت."},
  {"question": "سوخت‌های هسته‌ای کدامند؟", "answer": "عمدتاً اورانیوم (مانند U-235) و پلوتونیوم که در راکتورهای هسته‌ای برای تولید گرما از طریق شکافت هسته‌ای استفاده می‌شوند."},
  {"question": "چالش‌های اصلی استفاده از سوخت‌های هسته‌ای چیست؟", "answer": "مدیریت پسماندهای رادیواکتیو، نگرانی‌های ایمنی راکتورها، خطر اشاعه سلاح‌های هسته‌ای."},
  {"question": "مزایای انرژی هسته‌ای چیست؟", "answer": "عدم تولید گاز گلخانه‌ای در حین کار، چگالی انرژی بسیار بالا، قابلیت تولید برق پایدار و در مقیاس بزرگ."},
  {"question": "سوخت‌های زیستی (Biofuels) چیستند؟", "answer": "سوخت‌هایی که از مواد آلی (زیست توده) مانند گیاهان، ضایعات کشاورزی و حیوانی به دست می‌آیند. مثال‌ها: اتانول، بیودیزل."},
  {"question": "مزایای سوخت‌های زیستی چیست؟", "answer": "تجدیدپذیر بودن، کاهش وابستگی به سوخت‌های فسیلی، پتانسیل کاهش انتشار گازهای گلخانه‌ای (در صورت تولید پایدار)."},
  {"question": "معایب سوخت‌های زیستی چیست؟", "answer": "رقابت با تولید غذا برای زمین و آب، مصرف بالای آب و کود، انتشار گازهای گلخانه‌ای در فرآیند تولید برخی انواع."},
  {"question": "هیدروژن (H2) به عنوان سوخت چه ویژگی‌هایی دارد؟", "answer": "هیدروژن چگالی انرژی بالایی دارد، در صورت احتراق تنها آب تولید می‌کند (بسیار پاک)، اما تولید، ذخیره‌سازی و حمل و نقل آن چالش‌برانگیز است."},
  {"question": "روش‌های تولید هیدروژن چیست؟", "answer": "اصلاح بخار گاز طبیعی (رایج‌ترین، اما با انتشار CO2)، الکترولیز آب (با استفاده از برق، اگر برق از منابع تجدیدپذیر باشد پاک است)، تجزیه زیستی."},
  {"question": "چرا هیدروژن به عنوان 'سوخت پاک' شناخته می‌شود؟", "answer": "زیرا فرآورده اصلی واکنش آن با اکسیژن، آب است و آلاینده‌های مضر یا گازهای گلخانه‌ای تولید نمی‌کند."},
  {"question": "ذخیره‌سازی انرژی (Energy Storage) چیست و چرا مهم است؟", "answer": "ذخیره‌سازی انرژی به معنای نگهداری انرژی تولید شده برای استفاده در زمان بعدی است. این امر برای تأمین پایداری شبکه‌هایی با منابع تجدیدپذیر متغیر (مانند خورشید و باد) حیاتی است."},
  {"question": "روش‌های رایج ذخیره‌سازی انرژی را نام ببرید.", "answer": "باتری‌ها (شیمیایی)، پمپ ذخیره‌ساز هیدروالکتریک، هوای فشرده، ذخیره‌سازی حرارتی، فلای‌ویل."},
  {"question": "چگونه باتری‌ها انرژی را ذخیره می‌کنند؟", "answer": "باتری‌ها انرژی الکتریکی را از طریق واکنش‌های شیمیایی برگشت‌پذیر ذخیره و آزاد می‌کنند."},
  {"question": "پمپ ذخیره‌ساز هیدروالکتریک چگونه کار می‌کند؟", "answer": "در زمان مازاد برق، آب را به مخزن بالایی پمپ می‌کنند و در زمان نیاز، آب را رها کرده و از توربین‌ها برای تولید برق استفاده می‌کنند."},
  {"question": "چگالی انرژی (Energy Density) چیست؟", "answer": "مقدار انرژی ذخیره شده در واحد جرم (Wh/kg) یا واحد حجم (Wh/L) یک ماده یا سیستم."},
  {"question": "چرا سوخت‌های فسیلی چگالی انرژی بالایی دارند؟", "answer": "به دلیل پیوندهای شیمیایی قوی بین هیدروژن و کربن که هنگام شکستن، مقدار زیادی انرژی آزاد می‌کنند."},
  {"question": "مقایسه چگالی انرژی سوخت‌های فسیلی، باتری‌ها و هیدروژن.", "answer": "سوخت‌های فسیلی بالاترین چگالی انرژی وزنی را دارند، باتری‌ها چگالی انرژی حجمی خوبی دارند و هیدروژن چگالی انرژی وزنی بالایی دارد اما چگالی حجمی آن پایین است."},
  {"question": "سوخت‌های گازی (مانند LNG و LPG) چه تفاوتی با گاز طبیعی دارند؟", "answer": "LNG (گاز طبیعی مایع) و LPG (گاز مایع نفتی) شکلی فشرده یا مایع شده از گازها برای حمل و نقل آسان‌تر هستند."},
  {"question": "کربن خنثی (Carbon Neutral) به چه معناست؟", "answer": "به معنای دستیابی به تعادل خالص بین انتشار دی‌اکسید کربن و حذف آن از اتمسفر، معمولاً از طریق کاهش انتشار و جبران باقی‌مانده."},
  {"question": "کربن صفر (Net Zero Carbon) چیست؟", "answer": "هدف نهایی کاهش انتشار گازهای گلخانه‌ای تا حد ممکن و خنثی کردن هرگونه انتشار باقی‌مانده تا رسیدن به صفر خالص."},
  {"question": "چرا استفاده از سوخت‌های تجدیدپذیر اهمیت دارد؟", "answer": "برای کاهش انتشار گازهای گلخانه‌ای، مقابله با تغییرات اقلیمی، تأمین امنیت انرژی و کاهش آلودگی هوا."},
  {"question": "انواع زیست توده (Biomass) قابل استفاده به عنوان سوخت چیست؟", "answer": "محصولات کشاورزی (مانند ذرت، نیشکر)، ضایعات چوب، زباله‌های شهری، فضولات حیوانی."},
  {"question": "فرآیند تولید بیودیزل چیست؟", "answer": "معمولاً از طریق فرآیندی به نام ترانس استریفیکاسیون، که در آن روغن‌های گیاهی یا چربی‌های حیوانی با الکل واکنش داده و بیودیزل تولید می‌کنند."},
  {"question": "فرآیند تولید اتانول زیستی چیست؟", "answer": "معمولاً از طریق تخمیر قندها (موجود در ذرت، نیشکر و غیره) توسط مخمرها."},
  {"question": "ذغال سنگ نارس (Peat) چیست و چه ارتباطی با سوخت‌های فسیلی دارد؟", "answer": "ذغال سنگ نارس ماده آلی نیمه فسیلی است که به عنوان مرحله اولیه تشکیل زغال سنگ در نظر گرفته می‌شود."},
  {"question": "کک (Coke) چیست و چه کاربردی دارد؟", "answer": "کک سوخت جامد غنی از کربن است که از حرارت دادن زغال سنگ در غیاب هوا تولید می‌شود و عمدتاً در صنعت فولادسازی استفاده می‌شود."},
  {"question": "متان هیدرات (Methane Hydrate) چیست؟", "answer": "ترکیب متان و آب که در شرایط فشار و دمای پایین در اعماق اقیانوس‌ها و مناطق یخ‌زده یافت می‌شود و پتانسیل به عنوان منبع انرژی را دارد."},
  {"question": "تفاوت بین سوخت جامد، مایع و گازی چیست؟", "answer": "در نحوه ذخیره‌سازی، حمل و نقل، احتراق و نیاز به تجهیزات متفاوت."},
